const { useState, useRef, useEffect, useCallback, createContext, useContext } = React;
  const ThemeContext = createContext('dark');
  const FontScaleContext = createContext(1);
  const useFontScale = () => useContext(FontScaleContext);
  const cs=e=>e.currentTarget.style;
  const FF='var(--font-large)',TC='var(--t-text)',TMC='var(--t-text-muted)',
        BG='var(--t-card)',SBG='var(--t-sidebar)',ACC='var(--t-accent)',
        CBR=`1.5px solid var(--t-card-border)`,ACB=`1.5px solid var(--t-accent)`;
  const hov=(el,bg,hbg)=>{el.onmouseenter=()=>el.style.background=hbg;el.onmouseleave=()=>el.style.background=bg;};


  const IMG = {
    'accumulo': 'data:image/png;base64,',
    'admin': 'data:image/png;base64,',
    'airflow': 'data:image/png;base64,',
    'consul': 'data:image/png;base64,',
    'documentation': 'data:image/png;base64,',
    'kibana': 'data:image/png;base64,',
    'nagios': 'data:image/png;base64,',
    'nifi': 'data:image/png;base64,',
    'nifiRegistry': 'data:image/png;base64,',
    'rdaDeployer': 'data:image/png;base64,',
    'spark': 'data:image/png;base64,',
    'unity': 'data:image/png;base64,'
  };

  const APG_LOGO_IMG = "data:image/png;base64,";

  function APGLogo({ collapsed }) {
    const handleClick = () => window.dispatchEvent(new CustomEvent('apg-logo-click'));
    return (
      <img
        src={APG_LOGO_IMG}
        alt="APG Tactical Deployment Platform"
        onClick={handleClick}
        title="Go to Home"
        style={{
          height: collapsed ? 40 : 80,
          width: 'auto',
          flexShrink: 0,
          cursor: 'pointer',
          transition: 'height 0.22s cubic-bezier(0.4,0,0.2,1), opacity 0.15s',
        }}
        onMouseEnter={e => cs(e).opacity = '0.8'}
        onMouseLeave={e => cs(e).opacity = '1'}
      />
    );
  }

  // App definitions
  const APPS = [
    { id: 'accumulo',     name: 'Accumulo',      icon: IMG.accumulo,      desc: 'Apache Accumulo is a robust, scalable, and high-performance distributed NoSQL database designed to handle large amounts of structured and semi-structured data. It is based on Google\'s BigTable design and is built on top of Apache Hadoop, Zookeeper, and Thrift. Accumulo supports robust, scalable, high performance data storage and retrieval.' },
    { id: 'admin',        name: 'Admin',          icon: IMG.admin,         desc: 'Central administration portal for managing users, roles, permissions, and system-wide configuration settings across the platform.' },
    { id: 'airflow',      name: 'Airflow',        icon: IMG.airflow,       desc: 'Airflow is an open-source tool to programmatically author, schedule, and monitor workflows. It is one of the most robust platforms used by Data Engineers for orchestrating workflows or pipelines. You can easily visualize your data pipelines\' dependencies, progress, logs, code, trigger tasks, and success status.\n\nWith Airflow, users can author workflows as Directed Acyclic Graphs (DAGs) of tasks. Airflow\'s rich user interface makes it easy to visualize pipelines running in production, monitor progress, and troubleshoot issues when needed. It connects with multiple data sources and can send an alert via email or Slack when a task completes or fails. Airflow is distributed, scalable, and flexible, making it well-suited to handle the orchestration of complex business logic.' },
    { id: 'consul',       name: 'Consul',         icon: IMG.consul,        desc: 'Consul is a service networking solution that enables teams to manage secure network connectivity between services, across on-prem, hybrid cloud, and multi-cloud environments and runtimes. Consul offers service discovery, service mesh, identity-based authorization, L7 traffic management, and secure service-to-service encryption.\n\nConsul provides a control plane that enables you to register, query, and secure services deployed across your network. The control plane is the part of the network infrastructure that maintains a central registry to track services and their respective IP addresses. It is a distributed system that runs on clusters of nodes, such as physical servers, cloud instances, virtual machines, or containers.' },
    { id: 'documentation',name: 'Documentation',  icon: IMG.documentation, desc: 'Access the full platform documentation, API references, guides, and tutorials to help you get the most out of every service.' },
    { id: 'kibana',       name: 'Kibana',         icon: IMG.kibana,        desc: 'Kibana is a powerful open-source data visualization and exploration tool designed for Elastic\'s Elasticsearch engine. It functions as a web-based UI for analyzing, monitoring, and visualizing large volumes of structured or unstructured data in real time, serving as the front-end to the ELK Stack (Elasticsearch, Logstash, Kibana).' },
    { id: 'nagios',       name: 'Nagios',         icon: IMG.nagios,        desc: 'Nagios is a widely used, open-source IT infrastructure monitoring application that tracks servers, network devices, and applications in real-time. It proactively monitors system health (CPU, memory, disk usage), services (SMTP, HTTP), and network protocols, alerting IT teams to potential issues before they cause downtime.' },
    { id: 'nifi',         name: 'NiFi',           icon: IMG.nifi,          desc: 'NiFi is an open-source, low-code data integration platform designed to automate and manage the flow of data between systems in real-time. Using a drag-and-drop web interface, it excels at capturing, transforming, routing, and delivering data (ETL/ELT) from various sources to destinations, supporting high-speed, secure, and reliable data pipelines.' },
    { id: 'nifiRegistry', name: 'NiFi Registry',  icon: IMG.nifiRegistry,  desc: 'NiFi Registry is a subproject of Apache NiFi that acts as a central repository for storing, managing, and versioning shared data flows and assets across multiple NiFi or MiNiFi instances. It enables DevOps practices, allowing users to track changes, manage flow versions, and migrate flows between development, testing, and production environments.' },
    { id: 'rdaDeployer',  name: 'RDA Deployer',   icon: IMG.rdaDeployer,   desc: 'A comprehensive toolset and command-line interface (CLI) designed to automate the installation, configuration, lifecycle management, and upgrades of RDAF platform components. This automates the deployment and lifecycle management of RDA platform components, microservices, and configuration bundles.' },
    { id: 'spark',        name: 'Apache Spark',   icon: IMG.spark,         desc: 'An Apache Spark application is a user-written program designed for large-scale data processing that runs on a distributed computing cluster. It consists of a Driver process and Executors, which are worker processes on different nodes that execute tasks in parallel. The application can perform various workloads, including batch processing, SQL queries, streaming analytics, and machine learning, often using high-level APIs in Python, Scala, Java, or R. It leverages in-memory computing to cache datasets, offering performance that can be significantly faster than traditional disk-based Hadoop MapReduce. These applications are managed by a cluster manager, such as Spark Standalone, YARN, or Kubernetes, and are designed to be fault-tolerant.' },
    { id: 'unity',        name: 'Unity',          icon: IMG.unity,         desc: 'A platform integration layer that unifies services, identity, and access management across the entire infrastructure ecosystem.' },
  ];

  const GRID_ROWS = [
    { slots: ['fav',  'notif'] },
    { slots: ['analytics', 'tutorials'] },
  ];
  const ALL_SLOTS = GRID_ROWS.flatMap(r => r.slots);
  const BASE_COLS = { fav: 1, notif: 1, analytics: 2, tutorials: 1 };

  // recentApps tracks globally clicked app IDs in order (most recent last)
  // We use a module-level ref approach via window
  const JOB_TITLE_APPS = {
    'Job Listing 1': ['accumulo','admin','airflow','consul'],
    'Job Listing 2': ['documentation','kibana','nagios','nifi'],
    'Job Listing 3': ['nifiRegistry','rdaDeployer','spark','unity'],
  };
  function AppTile({ app, onAppClick, animDelay, isFavorited, onFavorite, onUnfavorite }) {
    const [hovered, setHovered] = useState(false);

    const handleStar = (e) => {
      e.stopPropagation();
      isFavorited ? onUnfavorite(app.id) : onFavorite(app.id);
    };

    return (
      <div
        className="app-tile-wrap"
        style={{ animationDelay: animDelay, position: 'relative' }}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
        onClick={() => onAppClick && onAppClick(app.id)}
      >
        {/* Star button — always visible when favorited, shown on hover otherwise */}
        {(hovered || isFavorited) && (
          <button
            onClick={handleStar}
            title={isFavorited ? 'Remove from favorites' : 'Add to favorites'}
            style={{
              position: 'absolute', top: 3, right: 3,
              width: 22, height: 22, borderRadius: '50%',
              background: isFavorited ? 'rgba(255,200,0,0.95)' : 'rgba(255,255,255,0.88)',
              border: isFavorited ? '1.5px solid rgba(200,150,0,0.6)' : '1.5px solid rgba(180,180,180,0.7)',
              cursor: 'pointer', zIndex: 20,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 12, lineHeight: 1, padding: 0,
              color: isFavorited ? '#7a5500' : '#bbb',
              boxShadow: '0 1px 5px rgba(0,0,0,0.18)',
              transition: 'transform 0.15s cubic-bezier(0.34,1.56,0.64,1), background 0.15s, color 0.15s',
              transform: hovered ? 'scale(1.18)' : 'scale(1)',
            }}
          >{isFavorited ? '★' : '☆'}</button>
        )}

        <div className="app-icon" style={{
          background: '#1a1a1a',
          backgroundImage: `url(${app.icon})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          transform: hovered ? 'scale(1.08) translateY(-2px)' : 'scale(1)',
          transition: 'transform 0.18s cubic-bezier(0.34,1.56,0.64,1)',
        }} />
        <div className="app-icon-label">{app.name}</div>
      </div>
    );
  }
  function AppDetailPopup({ app, onLaunch, onBack }) {
    const [dontShow, setDontShow] = useState(false);
    const fs = useFontScale();
    if (!app) return null;

    const handleLaunch = () => onLaunch(dontShow);
    const handleBack   = () => onBack(dontShow);

    return (
      <div
        onClick={() => handleBack()}
        style={{
          position: 'fixed', inset: 0,
          background: 'rgba(0,0,0,0.45)',
          zIndex: 600,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          animation: 'menuIn 0.18s cubic-bezier(0.34,1.56,0.64,1)',
        }}
      >
        <div
          onClick={e => e.stopPropagation()}

          style={{
            background: BG,
            borderRadius: 16,
            width: 520,
            boxShadow: '0 24px 64px rgba(0,0,0,0.28)',
            overflow: 'hidden',
            animation: 'menuIn 0.22s cubic-bezier(0.34,1.56,0.64,1)',
          }}
        >
          {/* Title bar */}
          <div style={{
            padding: '16px 20px',
            borderBottom: CBR,
            fontSize: 20 * fs, fontWeight: 700, fontFamily: FF, color: TC,
          }}>
            {app.name}
          </div>

          {/* Body: left col (icon + buttons + checkbox) | right col (description) */}
          <div style={{ display: 'flex', minHeight: 200 }}>

            {/* Left column */}
            <div style={{
              width: 200, flexShrink: 0,
              borderRight: CBR,
              display: 'flex', flexDirection: 'column',
              alignItems: 'center', justifyContent: 'space-between',
              padding: '24px 16px 16px',
              gap: 14,
            }}>
              {/* App icon */}
              <div style={{
                width: 110, height: 110, borderRadius: 22, flexShrink: 0,
                background: '#1a1a1a',
                backgroundImage: `url(${app.icon})`,
                backgroundSize: 'cover', backgroundPosition: 'center',
                boxShadow: '0 6px 20px rgba(0,0,0,0.18)',
              }} />

              {/* Buttons */}
              <div style={{ display: 'flex', gap: 8, width: '100%' }}>
                <button
                  onClick={handleBack}
                  style={{
                    flex: 1, padding: '9px 0',
                    borderRadius: 8, cursor: 'pointer',
                    background: SBG, border: `1px solid var(--t-card-border)`,
                    fontSize: 13 * fs, fontWeight: 700, fontFamily: FF, color: TC,
                    transition: 'background 0.12s',
                  }}
                  onMouseEnter={e => cs(e).background = 'var(--t-restore-bg)'}
                  onMouseLeave={e => cs(e).background = SBG}
                >BACK</button>
                <button
                  onClick={handleLaunch}
                  style={{
                    flex: 1, padding: '9px 0',
                    borderRadius: 8, cursor: 'pointer',
                    background: ACC, border: 'none',
                    color: BG, fontSize: 13 * fs, fontWeight: 700,
                    fontFamily: FF,
                    transition: 'opacity 0.12s',
                  }}
                  onMouseEnter={e=>cs(e).opacity='0.8'} onMouseLeave={e=>cs(e).opacity='1'}
                >LAUNCH</button>
              </div>

              {/* Don't show again checkbox */}
              <label style={{
                display: 'flex', alignItems: 'center', gap: 7,
                fontSize: 12 * fs, color: TMC, cursor: 'pointer',
                userSelect: 'none', alignSelf: 'flex-start',
              }}>
                <input
                  type="checkbox"
                  checked={dontShow}
                  onChange={e => setDontShow(e.target.checked)}
                  style={{ width: 14, height: 14, cursor: 'pointer', accentColor: ACC }}
                />
                Don't show this again
              </label>
            </div>

            {/* Right column — description */}
            <div style={{
              flex: 1, padding: '20px 22px',
              overflowY: 'auto', maxHeight: 280,
            }}>
              <div style={{ fontSize: 18 * fs, fontWeight: 700, fontFamily: FF, color: TC, marginBottom: 10 }}>
                Description
              </div>
              <p style={{ margin: 0, fontSize: 13.5 * fs, color: TMC, lineHeight: 1.7, whiteSpace: 'pre-line' }}>
                {app.desc}
              </p>
            </div>
          </div>
        </div>
      </div>
    );
  }
  function AppsOverlay({ phase, onClose, recentAppIds, onAppClick, favoritedAppIds, onFavorite, onUnfavorite, skippedAppIds, setSkippedAppIds }) {
    const panelRef = useRef(null);
    const [searchVal, setSearchVal] = useState('');
    const [selectedApp, setSelectedApp] = useState(null);

    const handleTileClick = (appId) => {
      if (skippedAppIds.has(appId)) {
        onAppClick(appId);
        setSearchVal('');
        return;
      }
      const app = APPS.find(a => a.id === appId);
      if (app) { setSelectedApp(app); setSearchVal(''); }
    };

    const handleLaunch = (dontShowAgain) => {
      if (selectedApp) {
        onAppClick(selectedApp.id);
        if (dontShowAgain) setSkippedAppIds(prev => new Set([...prev, selectedApp.id]));
        setSelectedApp(null);
      }
    };

    const handleBack = (dontShowAgain) => {
      if (dontShowAgain && selectedApp) setSkippedAppIds(prev => new Set([...prev, selectedApp.id]));
      setSelectedApp(null);
    };

    useEffect(() => {
      const el = panelRef.current; if (!el) return;
      const o = window.__appsOrigin; if (!o) return;
      el.style.transformOrigin = `${o.ox} ${o.oy}`;
      el.style.setProperty('--scale-from', `scale(${o.sx}, ${o.sy})`);
    });

    if (phase === 'hidden') return null;

    const isAnimating = phase === 'is-entering' || phase === 'is-open';

    // Favorited
    const favoritedApps = favoritedAppIds
      .map(id => APPS.find(a => a.id === id))
      .filter(Boolean);

    // Recent: only the 6 most recently clicked apps
    const recentApps = recentAppIds
      .slice(0, 6)
      .map(id => APPS.find(a => a.id === id))
      .filter(Boolean);

    const allCategories = [
      { title: 'Favorites', apps: favoritedApps, alwaysShow: true, emptyText: null },
      { title: 'Recent Apps', apps: recentApps, alwaysShow: true, emptyText: 'Click on an app, your most recent apps will appear here.' },
      ...Object.entries(JOB_TITLE_APPS).map(([title, ids]) => ({
        title,
        apps: ids.map(id => APPS.find(a => a.id === id)).filter(Boolean),
        alwaysShow: true,
      })),
    ];

    // Filter by search
    const q = searchVal.toLowerCase().trim();

    // Helper: find best description snippet containing the query
    function getDescSnippet(desc, query) {
      if (!desc || !query) return null;
      const lowerDesc = desc.toLowerCase();
      const idx = lowerDesc.indexOf(query);
      if (idx === -1) return null;
      // Extract ~60 chars around the match
      const CONTEXT = 36;
      const start = Math.max(0, idx - CONTEXT);
      const end   = Math.min(desc.length, idx + query.length + CONTEXT);
      const prefix = start > 0 ? '…' : '';
      const suffix = end < desc.length ? '…' : '';
      const before = desc.slice(start, idx);
      const match  = desc.slice(idx, idx + query.length);
      const after  = desc.slice(idx + query.length, end);
      return { prefix, before, match, after, suffix };
    }

    // Highlight component for description snippets
    function DescSnippet({ snippet }) {
      if (!snippet) return null;
      return (
        <span style={{ fontSize: 12, color: TMC, fontStyle: 'italic', marginTop: 1, lineHeight: 1.4 }}>
          {snippet.prefix}{snippet.before}
          <strong style={{ color: TC, fontStyle: 'normal', fontWeight: 700 }}>{snippet.match}</strong>
          {snippet.after}{snippet.suffix}
        </span>
      );
    }

    // When searching: show all apps alphabetically grouped by first letter
    // Match by name OR description
    let searchGroups = null;
    if (q) {
      const matchedApps = APPS
        .filter(a => a.name.toLowerCase().includes(q) || a.desc.toLowerCase().includes(q))
        .sort((a, b) => a.name.localeCompare(b.name))
        .map(app => ({
          ...app,
          _nameMatch: app.name.toLowerCase().includes(q),
          _descSnippet: !app.name.toLowerCase().includes(q)
            ? getDescSnippet(app.desc, q)
            : null,
        }));
      const byLetter = {};
      matchedApps.forEach(app => {
        const letter = app.name[0].toUpperCase();
        if (!byLetter[letter]) byLetter[letter] = [];
        byLetter[letter].push(app);
      });
      searchGroups = Object.entries(byLetter).sort(([a], [b]) => a.localeCompare(b));
    }

    const filtered = q
      ? null
      : allCategories.filter(c => c.alwaysShow || c.apps.length > 0);

    let globalIdx = 0;
    return (
      <>
        <div className={`apps-panel ${phase}`} ref={panelRef}>
          <div className="apps-inner">
            <div className="apps-header">
              <APGLogo />
              <div className="apps-logo">APPS</div>
              <div style={{ flex: 1, display: 'flex', alignItems: 'center', gap: 8 }}>
                {searchVal && (
                  <button
                    onClick={() => setSearchVal('')}
                    style={{
                      flexShrink: 0,
                      background: SBG, border: `1px solid var(--t-card-border)`,
                      borderRadius: 20, padding: '5px 12px',
                      fontSize: 12, fontWeight: 600, color: TMC,
                      cursor: 'pointer', fontFamily: FF,
                      transition: 'background 0.12s',
                      whiteSpace: 'nowrap',
                    }}
                    onMouseEnter={e => cs(e).background = 'var(--t-restore-bg)'}
                    onMouseLeave={e => cs(e).background = SBG}
                  >Clear</button>
                )}
                <input
                  className="apps-search"
                  type="text"
                  placeholder="Search apps..."
                  value={searchVal}
                  onChange={e => setSearchVal(e.target.value)}
                  style={{ flex: 1, minWidth: 0 }}
                />
              </div>
              <button className="apps-close-btn" onClick={onClose}>✕</button>
            </div>

            {searchGroups ? (
              searchGroups.length === 0 ? (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: 180, color: TMC, fontSize: 16, fontWeight: 600 }}>
                  No apps found
                </div>
              ) : (
                searchGroups.map(([letter, apps]) => (
                  <div key={letter}>
                    <div style={{ fontSize: 36, fontWeight: 900, fontFamily: FF, letterSpacing: '-1px', color: TC, margin: '8px 0 14px 2px', lineHeight: 1 }}>{letter}</div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 4, marginBottom: 28 }}>
                      {apps.map((app) => {
                        const delay = isAnimating ? `${0.28 + globalIdx++ * 0.022}s` : '0s';
                        // Highlight matching chars in name
                        const lowerName = app.name.toLowerCase();
                        const nameMatchIdx = lowerName.indexOf(q);
                        const nameHighlight = nameMatchIdx !== -1 ? (
                          <span style={{ fontSize: 15, fontWeight: 600, color: TC }}>
                            {app.name.slice(0, nameMatchIdx)}
                            <strong style={{ background: '#fff3b0', borderRadius: 2, padding: '0 1px', color: '#111' }}>
                              {app.name.slice(nameMatchIdx, nameMatchIdx + q.length)}
                            </strong>
                            {app.name.slice(nameMatchIdx + q.length)}
                          </span>
                        ) : (
                          <span style={{ fontSize: 15, fontWeight: 600, color: TC }}>{app.name}</span>
                        );

                        return (
                          <div
                            key={app.id}
                            onClick={() => handleTileClick(app.id)}
                            style={{
                              display: 'flex', alignItems: 'center', gap: 14,
                              padding: '8px 10px', borderRadius: 10, cursor: 'pointer',
                              transition: 'background 0.13s',
                              animationDelay: delay,
                            }}
                            onMouseEnter={e => cs(e).background = SBG}
                            onMouseLeave={e => cs(e).background = 'transparent'}
                          >
                            <div style={{
                              width: 48, height: 48, borderRadius: 12, flexShrink: 0,
                              background: '#1a1a1a',
                              backgroundImage: `url(${app.icon})`,
                              backgroundSize: 'cover', backgroundPosition: 'center',
                            }} />
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 2, minWidth: 0 }}>
                              {nameHighlight}
                              {app._descSnippet && <DescSnippet snippet={app._descSnippet} />}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))
              )
            ) : (
              filtered.map((cat, ci) => (
                <div key={ci}>
                  <div className="apps-section-title">{cat.title}</div>
                  {cat.apps.length === 0 ? (
                    <div style={{
                      display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                      gap: 10, marginBottom: 36,
                      height: 110,
                      background: cat.title === 'Favorites'
                        ? 'rgba(240,200,60,0.13)'
                        : 'rgba(120,120,120,0.08)',
                      border: cat.title === 'Favorites'
                        ? '1.5px dashed #f0d060'
                        : `1.5px dashed var(--t-card-border)`,
                      borderRadius: 16,
                    }}>
                      <span style={{ fontSize: 28, lineHeight: 1 }}>
                        {cat.title === 'Favorites' ? '⭐' : '🕐'}
                      </span>
                      <p style={{
                        margin: 0, textAlign: 'center',
                        fontSize: 14, fontWeight: 600,
                        lineHeight: 1.5, maxWidth: 340,
                        color: cat.title === 'Favorites' ? '#a07800' : TMC,
                      }}>
                        {cat.title === 'Favorites'
                          ? <span>Click the star icon on the top right of an app logo to favorite an app!</span>
                          : 'Click on an app, your most recent apps will appear here.'
                        }
                      </p>
                    </div>
                  ) : (
                    <div className="apps-grid">
                      {cat.apps.map((app) => {
                        const delay = isAnimating ? `${0.28 + globalIdx++ * 0.022}s` : '0s';
                        return (
                          <AppTile
                            key={app.id}
                            app={app}
                            onAppClick={handleTileClick}
                            animDelay={delay}
                            isFavorited={favoritedAppIds.includes(app.id)}
                            onFavorite={onFavorite}
                            onUnfavorite={onUnfavorite}
                          />
                        );
                      })}
                    </div>
                  )}
                </div>
              ))
            )}
          </div>
        </div>

        {selectedApp && (
          <AppDetailPopup
            app={selectedApp}
            onLaunch={handleLaunch}
            onBack={handleBack}
          />
        )}
      </>
    );
  }
  const _today = new Date();
  const _isoToday = `${_today.getFullYear()}-${String(_today.getMonth()+1).padStart(2,'0')}-${String(_today.getDate()).padStart(2,'0')}`;
  const _isoPrev  = d => { const x = new Date(_today); x.setDate(x.getDate() - d); return x.toISOString().split('T')[0]; };
  const _isoNext  = d => { const x = new Date(_today); x.setDate(x.getDate() + d); return x.toISOString().split('T')[0]; };

  const SAMPLE_NOTIFICATIONS = [
    { id: 1, accent: '#dc2626', label: 'ERROR',   category: 'System',    title: 'Server Issue',        body: 'DB-prod-01 is unresponsive — NiFi & Spark services may be affected.', time: 'Today', dashTime: '3 min ago',  unread: true,  isoDate: _isoToday },
    { id: 3, accent: '#16a34a', label: 'ACTIVITY', category: 'Activity',  title: 'Deployment Complete', body: 'RDA Deployer finished deploying v2.5.0 to production.',               time: '28 min ago', unread: false, isoDate: _isoPrev(1) },
  ];
  function NotifCalendar({ notifications, onClose }) {
    const today = new Date();
    const [viewYear,  setViewYear]  = useState(today.getFullYear());
    const [viewMonth, setViewMonth] = useState(today.getMonth());
    const [tooltip, setTooltip]     = useState(null); // { iso, rect }
    const hideTimerRef = useRef(null);

    const byDate = {};
    notifications.forEach(n => {
      if (!n.isoDate) return;
      if (!byDate[n.isoDate]) byDate[n.isoDate] = [];
      byDate[n.isoDate].push(n);
    });

    const prevMonth = () => {
      if (viewMonth === 0) { setViewMonth(11); setViewYear(y => y - 1); }
      else setViewMonth(m => m - 1);
    };
    const nextMonth = () => {
      if (viewMonth === 11) { setViewMonth(0); setViewYear(y => y + 1); }
      else setViewMonth(m => m + 1);
    };

    const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
    const dayNames   = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];

    const firstDow    = new Date(viewYear, viewMonth, 1).getDay();
    const daysInMonth = new Date(viewYear, viewMonth + 1, 0).getDate();
    const todayIso    = (() => { const t = new Date(); return `${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,'0')}-${String(t.getDate()).padStart(2,'0')}`; })();

    const cells = [];
    for (let i = 0; i < firstDow; i++) cells.push(null);
    for (let d = 1; d <= daysInMonth; d++) {
      cells.push(`${viewYear}-${String(viewMonth+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`);
    }
    while (cells.length % 7 !== 0) cells.push(null);

    const CAT_COLORS = { System: '#dc2626', Reminders: '#d97706', Activity: '#16a34a' };
    const CAT_BG     = { System: 'rgba(220,38,38,0.10)', Reminders: 'rgba(217,119,6,0.10)', Activity: 'rgba(22,163,74,0.10)' };

    // Render tooltip via portal into body to escape any CSS filter stacking context
    const tooltipPortal = tooltip && byDate[tooltip.iso] ? ReactDOM.createPortal((() => {
      const events = byDate[tooltip.iso];
      const r      = tooltip.rect;
      const tipW   = 220;
      const spaceRight = window.innerWidth - r.right;
      const leftPos = spaceRight >= tipW + 10 ? r.right + 8 : r.left - tipW - 8;
      const topPos  = Math.max(8, Math.min(r.top, window.innerHeight - 120));
      const maxH    = window.innerHeight - topPos - 16;
      return (
        <div style={{
          position: 'fixed', top: topPos, left: leftPos, width: tipW,
          zIndex: 99999,
          background: BG,
          borderRadius: 14,
          boxShadow: '0 8px 32px rgba(0,0,0,0.18), 0 2px 8px rgba(0,0,0,0.10)',
          border: '1.5px solid var(--t-card-border)',
          padding: '10px 12px',
          animation: 'menuIn 0.15s cubic-bezier(0.34,1.56,0.64,1)',
          maxHeight: maxH,
          display: 'flex',
          flexDirection: 'column',
        }}
        onMouseEnter={() => clearTimeout(hideTimerRef.current)}
        onMouseLeave={() => { hideTimerRef.current = setTimeout(() => setTooltip(null), 150); }}>
          <div style={{ fontSize: 11, fontWeight: 700, fontFamily: FF, color: TMC, textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 8, flexShrink: 0 }}>
            {monthNames[parseInt(tooltip.iso.split('-')[1],10)-1]} {parseInt(tooltip.iso.split('-')[2],10)}
          </div>
          <div style={{ overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 8 }}>
            {events.map((n, i) => (
              <div key={n.id ?? i} style={{
                padding: '8px 10px',
                borderRadius: 10,
                background: CAT_BG[n.category] || SBG,
                borderLeft: `3px solid ${CAT_COLORS[n.category] || TMC}`,
                flexShrink: 0,
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 5, marginBottom: 3 }}>
                  <span style={{
                    fontSize: 9, fontWeight: 800, fontFamily: FF,
                    background: CAT_COLORS[n.category] || '#888',
                    color: '#fff', borderRadius: 4, padding: '1px 5px',
                    letterSpacing: '0.04em', textTransform: 'uppercase',
                  }}>{n.label || n.category}</span>
                  {n.unread && <div style={{ width: 6, height: 6, borderRadius: '50%', background: CAT_COLORS[n.category] || '#888', flexShrink: 0 }} />}
                </div>
                <div style={{ fontSize: 12, fontWeight: 700, fontFamily: FF, color: TC, lineHeight: 1.3, marginBottom: 2 }}>{n.title}</div>
                <div style={{ fontSize: 11, color: TMC, fontFamily: FF, lineHeight: 1.4, overflow: 'hidden', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical' }}>{n.body}</div>
                {n.scheduledLabel && <div style={{ fontSize: 10, color: '#d97706', fontWeight: 700, marginTop: 3 }}>🗓 {n.scheduledLabel}</div>}
              </div>
            ))}
          </div>
        </div>
      );
    })(), document.body) : null;

    return (
      <div
        onClick={e => e.stopPropagation()}
        style={{
          background: BG,
          borderRadius: 20,
          boxShadow: '0 16px 56px rgba(0,0,0,0.18), 0 2px 8px rgba(0,0,0,0.08)',
          width: 640,
          padding: '20px 22px 18px',
          animation: 'menuIn 0.22s cubic-bezier(0.34,1.56,0.64,1)',
        }}
      >
        {tooltipPortal}

        {/* Month nav */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
          <button onClick={prevMonth} style={{ background: 'none', border: CBR, borderRadius: 9, width: 38, height: 38, cursor: 'pointer', fontSize: 20, display: 'flex', alignItems: 'center', justifyContent: 'center', color: TC, transition: 'background 0.12s' }}
            onMouseEnter={e=>cs(e).background=SBG} onMouseLeave={e=>cs(e).background='none'}>‹</button>
          <div style={{ fontWeight: 800, fontFamily: FF, fontSize: 21, color: TC, letterSpacing: '-0.3px' }}>
            {monthNames[viewMonth]} {viewYear}
          </div>
          <button onClick={nextMonth} style={{ background: 'none', border: CBR, borderRadius: 9, width: 38, height: 38, cursor: 'pointer', fontSize: 20, display: 'flex', alignItems: 'center', justifyContent: 'center', color: TC, transition: 'background 0.12s' }}
            onMouseEnter={e=>cs(e).background=SBG} onMouseLeave={e=>cs(e).background='none'}>›</button>
        </div>

        {/* Day-of-week headers */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7,1fr)', gap: 4, marginBottom: 6 }}>
          {dayNames.map(d => (
            <div key={d} style={{ textAlign: 'center', fontSize: 12, fontWeight: 700, color: TMC, letterSpacing: '0.06em', textTransform: 'uppercase', paddingBottom: 6 }}>{d}</div>
          ))}
        </div>

        {/* Calendar grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7,1fr)', gap: 4 }}>
          {cells.map((iso, idx) => {
            if (!iso) return <div key={`e-${idx}`} />;
            const dayNum    = parseInt(iso.split('-')[2], 10);
            const isToday   = iso === todayIso;
            const events    = byDate[iso] || [];
            const hasEvents   = events.length > 0;
            const hasSystem   = events.some(n => n.category === 'System');
            const hasReminder = events.some(n => n.category === 'Reminders');
            const hasActivity = events.some(n => n.category === 'Activity');

            return (
              <div key={iso} style={{
                borderRadius: 12,
                padding: '6px 5px 5px',
                height: 66,
                overflow: 'hidden',
                background: isToday ? 'rgba(120,120,120,0.12)' : 'transparent',
                border: isToday ? '1.5px solid #888888' : CBR,
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4,
                transition: 'background 0.12s',
                cursor: hasEvents ? 'pointer' : 'default',
              }}
              onMouseEnter={e => {
                clearTimeout(hideTimerRef.current);
                if (!isToday) cs(e).background = SBG;
                if (hasEvents) setTooltip({ iso, rect: e.currentTarget.getBoundingClientRect() });
              }}
              onMouseLeave={e => {
                if (!isToday) cs(e).background = 'transparent';
                hideTimerRef.current = setTimeout(() => setTooltip(null), 150);
              }}
              >
                <div style={{
                  fontWeight: isToday ? 800 : 500,
                  fontSize: 15,
                  color: isToday ? '#555555' : TC,
                  lineHeight: 1, marginBottom: 2, flexShrink: 0,
                }}>{dayNum}</div>

                <div style={{ display: 'flex', flexDirection: 'column', gap: 3, width: '100%', alignItems: 'stretch', overflow: 'hidden', minWidth: 0 }}>
                  {hasSystem && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'rgba(220,38,38,0.15)', borderRadius: 5, padding: '3px 5px', overflow: 'hidden', minWidth: 0 }}>
                      <div style={{ width: 7, height: 7, borderRadius: '50%', background: '#dc2626', flexShrink: 0 }} />
                      <span style={{ fontSize: 10, fontFamily: FF, fontWeight: 700, color: '#dc2626', lineHeight: 1.2, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', minWidth: 0 }}>
                        {events.filter(n=>n.category==='System').map(n=>n.title).join(', ')}
                      </span>
                    </div>
                  )}
                  {hasReminder && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'rgba(217,119,6,0.15)', borderRadius: 5, padding: '3px 5px', overflow: 'hidden', minWidth: 0 }}>
                      <div style={{ width: 7, height: 7, borderRadius: '50%', background: '#d97706', flexShrink: 0 }} />
                      <span style={{ fontSize: 10, fontFamily: FF, fontWeight: 700, color: '#d97706', lineHeight: 1.2, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', minWidth: 0 }}>
                        {events.filter(n=>n.category==='Reminders').map(n=>n.title).join(', ')}
                      </span>
                    </div>
                  )}
                  {hasActivity && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'rgba(22,163,74,0.15)', borderRadius: 5, padding: '3px 5px', overflow: 'hidden', minWidth: 0 }}>
                      <div style={{ width: 7, height: 7, borderRadius: '50%', background: '#16a34a', flexShrink: 0 }} />
                      <span style={{ fontSize: 10, fontFamily: FF, fontWeight: 700, color: '#16a34a', lineHeight: 1.2, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', minWidth: 0 }}>
                        {events.filter(n=>n.category==='Activity').map(n=>n.title).join(', ')}
                      </span>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* Legend */}
        <div style={{ display: 'flex', gap: 20, marginTop: 18, paddingTop: 14, borderTop: CBR, justifyContent: 'center' }}>
          {[['#dc2626','System Error'],['#d97706','Reminder'],['#16a34a','Activity']].map(([dot,label]) => (
            <div key={label} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <div style={{ width: 10, height: 10, borderRadius: '50%', background: dot }} />
              <span style={{ fontSize: 13, color: TMC, fontWeight: 600 }}>{label}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }

  const NOTIF_CATEGORIES = ['All', 'System', 'Reminders', 'Activity'];

  function NotificationsOverlay({ phase, onClose, notifications, markAllRead, markRead, markUnread, dismiss, addNotification }) {
    const panelRef = useRef(null);
    const fs = useFontScale();
    const [selectedCat, setSelectedCat] = useState('All');
    const [showPopup, setShowPopup]     = useState(false);
    const [showCalendar, setShowCalendar] = useState(false);
    const [popupDate, setPopupDate]     = useState('');
    const [popupTime, setPopupTime]     = useState('');
    const [popupTitle, setPopupTitle]   = useState('');
    const [popupDesc, setPopupDesc]     = useState('');
    const [showPastDateError, setShowPastDateError] = useState(false);
    const [pastDateErrorMsg, setPastDateErrorMsg]   = useState('');

    useEffect(() => {
      const el = panelRef.current; if (!el) return;
      const o = window.__notifOrigin; if (!o) return;
      el.style.transformOrigin = `${o.ox} ${o.oy}`;
      el.style.setProperty('--scale-from', `scale(${o.sx}, ${o.sy})`);
    });

    if (phase === 'hidden') return null;

    const unreadCount = notifications.filter(n => n.unread).length;
    const baseList = selectedCat === 'All' ? notifications : notifications.filter(n => n.category === selectedCat);
    const filtered = [...baseList].sort((a, b) => (b.pinned ? 1 : 0) - (a.pinned ? 1 : 0));

    const catAccent = { System: '#dc2626', Reminders: '#d97706', Activity: '#16a34a' };
    const catUnread = (cat) => cat === 'All'
      ? notifications.filter(n => n.unread).length
      : notifications.filter(n => n.category === cat && n.unread).length;

    return (
      <div className={`apps-panel ${phase}`} ref={panelRef} style={{ display: 'flex', flexDirection: 'row' }}>
<div style={{
          width: 200, flexShrink: 0,
          borderRight: CBR,
          background: SBG,
          display: 'flex', flexDirection: 'column',
          padding: '28px 0 28px',
        }}>
          <div style={{ fontWeight: 700, fontSize: 13 * fs, fontFamily: FF, color: TMC, letterSpacing: '0.07em', textTransform: 'uppercase', padding: '0 20px', marginBottom: 12 }}>Categories</div>
          {NOTIF_CATEGORIES.map(cat => {
            const active = selectedCat === cat;
            const count  = catUnread(cat);
            const accent = cat === 'All' ? TMC : catAccent[cat];
            return (
              <button
                key={cat}
                onClick={() => setSelectedCat(cat)}
                style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                  width: '100%', padding: '10px 20px',
                  background: active ? BG : 'none',
                  border: 'none',
                  borderLeft: active ? `3px solid ${accent}` : '3px solid transparent',
                  cursor: 'pointer', fontFamily: FF,
                  fontSize: 14 * fs, fontWeight: active ? 700 : 500,
                  color: active ? TC : TMC,
                  transition: 'background 0.13s, color 0.13s',
                  textAlign: 'left',
                }}
                onMouseEnter={e => { if (!active) cs(e).background = 'var(--t-restore-bg)'; }}
                onMouseLeave={e => { if (!active) cs(e).background = 'none'; }}
              >
                <span>{cat}</span>
                {count > 0 && (
                  <span style={{
                    background: accent, color: '#fff',
                    borderRadius: 20, padding: '1px 7px', fontSize: 11 * fs, fontWeight: 700, fontFamily: FF,
                  }}>{count}</span>
                )}
              </button>
            );
          })}
<div style={{ marginTop: 'auto', padding: '0 16px' }}>
            <button
              onClick={() => setShowPopup(true)}
              style={{
                width: '100%', padding: '10px',
                background: ACC, color: BG,
                border: 'none', borderRadius: 10,
                fontWeight: 700, fontSize: 20, cursor: 'pointer',
                fontFamily: FF, lineHeight: 1,
                transition: 'opacity 0.14s',
              }}
              onMouseEnter={e=>cs(e).opacity='0.8'} onMouseLeave={e=>cs(e).opacity='1'}
              title="Add reminder"
            >+</button>
          </div>
        </div>
{showPopup && (
          <div
            onClick={() => setShowPopup(false)}
            style={{
              position: 'fixed', inset: 0, zIndex: 600,
              background: 'rgba(0,0,0,0.35)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}
          >
            <div
              onClick={e => e.stopPropagation()}

              style={{
                background: BG, borderRadius: 16,
                padding: '28px 28px 24px',
                width: 380, boxShadow: '0 20px 60px rgba(0,0,0,0.22)',
                display: 'flex', flexDirection: 'column', gap: 16,
                animation: 'menuIn 0.2s cubic-bezier(0.34,1.56,0.64,1)',
              }}
            >
              <div style={{ fontWeight: 800, fontFamily: FF, fontSize: 18, color: TC }}>Add Reminder</div>

              {/* Date */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: TMC, fontFamily: FF, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Date</label>
                <input
                  type="date"
                  value={popupDate}
                  onChange={e => setPopupDate(e.target.value)}
                  style={{
                    padding: '9px 12px', borderRadius: 8,
                    border: CBR, fontSize: 14,
                    fontFamily: FF, outline: 'none',
                    background: SBG, color: TC,
                    transition: 'border-color 0.15s',
                  }}
                  onFocus={e => e.target.style.borderColor = TMC}
                  onBlur={e => e.target.style.borderColor = 'var(--t-card-border)'}
                />
              </div>

              {/* Time (optional) */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: TMC, fontFamily: FF, textTransform: 'uppercase', letterSpacing: '0.05em', display: 'flex', alignItems: 'center', gap: 6 }}>
                  Time
                  <span style={{ fontSize: 10, fontFamily: FF, fontWeight: 500, color: TMC, textTransform: 'none', letterSpacing: 0, opacity: 0.7 }}>(optional)</span>
                </label>
                <input
                  type="time"
                  value={popupTime}
                  onChange={e => setPopupTime(e.target.value)}
                  style={{
                    padding: '9px 12px', borderRadius: 8,
                    border: CBR, fontSize: 14,
                    fontFamily: FF, outline: 'none',
                    background: SBG,
                    transition: 'border-color 0.15s',
                    color: TC,
                  }}
                  onFocus={e => e.target.style.borderColor = TMC}
                  onBlur={e => e.target.style.borderColor = 'var(--t-card-border)'}
                />
              </div>

              {/* Title */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: TMC, fontFamily: FF, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Title</label>
                <input
                  type="text"
                  placeholder="Reminder title..."
                  value={popupTitle}
                  onChange={e => setPopupTitle(e.target.value)}
                  style={{
                    padding: '9px 12px', borderRadius: 8,
                    border: CBR, fontSize: 14,
                    fontFamily: FF, outline: 'none',
                    background: SBG, color: TC,
                    transition: 'border-color 0.15s',
                  }}
                  onFocus={e => e.target.style.borderColor = TMC}
                  onBlur={e => e.target.style.borderColor = 'var(--t-card-border)'}
                />
              </div>

              {/* Description */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: TMC, fontFamily: FF, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Description</label>
                <textarea
                  placeholder="Add a description..."
                  value={popupDesc}
                  onChange={e => setPopupDesc(e.target.value)}
                  rows={3}
                  style={{
                    padding: '9px 12px', borderRadius: 8,
                    border: CBR, fontSize: 14,
                    fontFamily: FF, outline: 'none', resize: 'vertical',
                    background: SBG, color: TC,
                    transition: 'border-color 0.15s',
                  }}
                  onFocus={e => e.target.style.borderColor = TMC}
                  onBlur={e => e.target.style.borderColor = 'var(--t-card-border)'}
                />
              </div>

              {/* Buttons */}
              <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}>
                <button
                  onClick={() => { setShowPopup(false); setPopupDate(''); setPopupTime(''); setPopupTitle(''); setPopupDesc(''); }}
                  style={{
                    padding: '9px 18px', borderRadius: 8, cursor: 'pointer',
                    background: 'none', border: CBR,
                    fontSize: 14, fontWeight: 600, fontFamily: FF, color: TMC,
                    transition: 'background 0.12s',
                  }}
                  onMouseEnter={e => cs(e).background = SBG}
                  onMouseLeave={e => cs(e).background = 'none'}
                >Cancel</button>
                <button
                  onClick={() => {
                    if (!popupDate || !popupTitle.trim()) return;
                    const now = new Date();
                    const todayIso = now.toISOString().split('T')[0];

                    if (!popupTime) {
                      // No time provided: block if date is today OR in the past
                      const today = new Date(); today.setHours(0,0,0,0);
                      const [_yr,_mo,_dy] = popupDate.split('-').map(Number);
                      const chosen = new Date(_yr, _mo-1, _dy); chosen.setHours(0,0,0,0);
                      if (chosen <= today) {
                        setPastDateErrorMsg('The date that you entered has already passed. In order to add a reminder, use a future date and/or time.');
                        setShowPastDateError(true); return;
                      }
                    } else {
                      // Time provided: block if the chosen date+time is less than 1 minute from now
                      // Parse manually in LOCAL time to avoid UTC offset issues
                      const [yr, mo, dy] = popupDate.split('-').map(Number);
                      const [hr, mn] = popupTime.split(':').map(Number);
                      const chosen = new Date(yr, mo - 1, dy, hr, mn, 0, 0);
                      const diffMs = chosen - now;
                      if (diffMs <= 0) {
                        setPastDateErrorMsg('The date that you entered has already passed. In order to add a reminder, use a future date and/or time.');
                        setShowPastDateError(true); return;
                      }
                    }

                    addNotification({ date: popupDate, time: popupTime, title: popupTitle.trim(), description: popupDesc.trim() || popupTitle.trim() });
                    setShowPopup(false); setPopupDate(''); setPopupTime(''); setPopupTitle(''); setPopupDesc('');
                    setSelectedCat('Reminders');
                  }}
                  style={{
                    padding: '9px 22px', borderRadius: 8, cursor: 'pointer',
                    background: popupDate && popupTitle.trim() ? ACC : 'var(--t-card-border)',
                    border: 'none', color: BG,
                    fontSize: 14, fontWeight: 700, fontFamily: FF,
                    transition: 'opacity 0.12s',
                  }}
                  onMouseEnter={e => { if (popupDate && popupTitle.trim()) cs(e).opacity = '0.8'; }}
                  onMouseLeave={e => { if (popupDate && popupTitle.trim()) cs(e).opacity = '1'; }}
                >Done</button>
              </div>
            </div>
          </div>
        )}
{showPastDateError && (
          <div
            onClick={() => { setShowPastDateError(false); setPastDateErrorMsg(''); }}
            style={{
              position: 'fixed', inset: 0, zIndex: 700,
              background: 'rgba(0,0,0,0.45)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}
          >
            <div
              onClick={e => e.stopPropagation()}
              style={{
                background: BG, borderRadius: 16,
                padding: '32px 28px 24px',
                width: 360, boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 16,
                animation: 'menuIn 0.22s cubic-bezier(0.34,1.56,0.64,1)',
                textAlign: 'center',
              }}
            >
              <div style={{ fontSize: 36, lineHeight: 1 }}>⚠️</div>
              <p style={{
                margin: 0, fontSize: 15, fontWeight: 600,
                fontFamily: FF, color: TC,
                lineHeight: 1.55,
              }}>
                {pastDateErrorMsg}
              </p>
              <button
                onClick={() => { setShowPastDateError(false); setPastDateErrorMsg(''); }}
                style={{
                  marginTop: 4,
                  padding: '10px 36px', borderRadius: 8, cursor: 'pointer',
                  background: ACC, border: 'none',
                  color: BG, fontSize: 14, fontWeight: 700,
                  fontFamily: FF,
                  transition: 'opacity 0.12s',
                }}
                onMouseEnter={e => cs(e).opacity = '0.8'}
                onMouseLeave={e => cs(e).opacity = '1'}
              >OK</button>
            </div>
          </div>
        )}
<div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 }}>
          <div className="apps-inner" style={{ flex: 1 }}>
<div style={{
              display: 'flex', justifyContent: 'center', alignItems: 'center',
              position: 'sticky', top: 0, zIndex: 20,
              background: BG, paddingTop: 20, paddingBottom: showCalendar ? 0 : 12,
              borderBottom: showCalendar ? 'none' : CBR,
              marginBottom: showCalendar ? 0 : 0,
              boxShadow: showCalendar ? 'none' : '0 4px 16px 0 var(--t-card)',
              paddingLeft: 20, paddingRight: 20,
            }}>
              {/* APG Logo anchored to the left */}
              <div style={{ position: 'absolute', left: 20 }}>
                <APGLogo />
              </div>
              <div style={{ position: 'relative', display: 'inline-flex', flexDirection: 'column', alignItems: 'center' }}>
                <button
                  onClick={() => setShowCalendar(v => !v)}
                  style={{
                    display: 'flex', alignItems: 'center', gap: 7,
                    padding: '8px 20px',
                    background: showCalendar ? ACC : SBG,
                    color: showCalendar ? BG : TC,
                    border: showCalendar ? ACB : CBR,
                    borderRadius: showCalendar ? '10px 10px 0 0' : 10,
                    cursor: 'pointer', fontFamily: FF,
                    fontSize: 14, fontWeight: 700, letterSpacing: '0.01em',
                    transition: 'background 0.15s, color 0.15s, border-color 0.15s',
                    borderBottom: showCalendar ? ACB : undefined,
                  }}
                  onMouseEnter={e => { if (!showCalendar) { cs(e).background='var(--t-restore-bg)'; } }}
                  onMouseLeave={e => { if (!showCalendar) { cs(e).background=SBG; } }}
                >
                  Calendar
                  <span style={{
                    display: 'inline-block',
                    transform: showCalendar ? 'rotate(180deg)' : 'rotate(0deg)',
                    transition: 'transform 0.2s',
                    fontSize: 11, opacity: 0.7, marginLeft: 2,
                  }}>▼</span>
                </button>

                {/* Dropdown calendar panel */}
                {showCalendar && (
                  <>
                    {/* Click-outside backdrop */}
                    <div
                      onClick={() => setShowCalendar(false)}
                      style={{ position: 'fixed', inset: 0, zIndex: 49 }}
                    />
                    <div style={{
                      position: 'absolute', top: '100%', left: '50%',
                      transform: 'translateX(-50%)',
                      zIndex: 50,
                      filter: 'drop-shadow(0 8px 32px rgba(0,0,0,0.14))',
                    }}>
                      {/* Connector nub */}
                      <div style={{
                        width: 14, height: 8,
                        background: ACC,
                        clipPath: 'polygon(0 0, 100% 0, 50% 100%)',
                        margin: '0 auto',
                        position: 'relative', zIndex: 2,
                        transform: 'translateY(1px)',
                      }} />
                      <NotifCalendar notifications={notifications} onClose={() => setShowCalendar(false)} />
                    </div>
                  </>
                )}
              </div>
            </div>

            {showCalendar && <div style={{ height: 12 }} />}

            <div className="apps-header" style={{ top: showCalendar ? 'auto' : 0 }}>
              <div className="apps-logo" style={{ fontSize: 20 }}>
                {selectedCat === 'All' ? 'Notifications' : selectedCat}
                {catUnread(selectedCat) > 0 && (
                  <span style={{
                    marginLeft: 10, background: selectedCat === 'All' ? '#e74c3c' : catAccent[selectedCat],
                    color: '#fff', borderRadius: 20, padding: '2px 9px', fontSize: 13, fontWeight: 700, fontFamily: FF,
                  }}>
                    {catUnread(selectedCat)}
                  </span>
                )}
              </div>
              <div style={{ flex: 1 }} />
              {unreadCount > 0 && (
                <button onClick={markAllRead} style={{
                  background: 'none', border: CBR, borderRadius: 8,
                  padding: '6px 14px', fontSize: 13, cursor: 'pointer',
                  fontFamily: FF, color: TMC, marginRight: 8,
                  transition: 'background 0.12s',
                }}
                onMouseEnter={e => cs(e).background = SBG}
                onMouseLeave={e => cs(e).background = 'none'}
                >Mark all read</button>
              )}
              <button className="apps-close-btn" onClick={onClose}>✕</button>
            </div>

            {filtered.length === 0 ? (
              <div style={{
                display: 'flex', flexDirection: 'column', alignItems: 'center',
                justifyContent: 'center', padding: '60px 24px', gap: 14, color: TMC,
              }}>
                <p style={{ margin: 0, fontSize: 16, fontWeight: 700, fontFamily: FF, color: TMC }}>No notifications</p>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 0 }}>
                {filtered.map((n, ni) => (
                  <div key={n.id} style={{
                    display: 'flex', alignItems: 'stretch',
                    borderRadius: 12, overflow: 'hidden', marginBottom: 10,
                    animation: `iconIn 0.34s cubic-bezier(0.34,1.56,0.64,1) ${0.06 + ni * 0.04}s both`,
                    boxShadow: n.unread ? `0 2px 8px rgba(0,0,0,0.07)` : 'none',
                    opacity: n.unread ? 1 : 0.72,
                  }}>
                    <div style={{ width: 6, flexShrink: 0, background: n.accent }} />
                    <div style={{
                      flex: 1, display: 'flex', flexDirection: 'column',
                      padding: '14px 16px',
                      background: n.unread ? BG : SBG,
                      borderTop: CBR,
                      borderRight: CBR,
                      borderBottom: CBR,
                      borderLeft: 'none', borderRadius: '0 12px 12px 0',
                      transition: 'background 0.2s', gap: 10,
                    }}>
                      <div style={{ display: 'flex', alignItems: 'flex-start', gap: 12 }}>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 5 }}>
                            {n.pinned && <span style={{ fontSize: 10 * fs, fontFamily: FF, fontWeight: 800, color: '#d97706', background: '#fff8e1', border: '1.5px solid #f0c040', borderRadius: 4, padding: '2px 7px', flexShrink: 0, letterSpacing: '0.04em' }}>📌 PINNED</span>}
                            <span style={{
                              fontSize: 10 * fs, fontFamily: FF, fontWeight: 800, letterSpacing: '0.06em',
                              color: '#fff', background: n.accent,
                              borderRadius: 4, padding: '2px 7px', flexShrink: 0,
                            }}>{n.label}</span>
                            <span style={{ fontWeight: 700, fontSize: 15 * fs, fontFamily: FF, color: TC }}>{n.title}</span>
                            {n.unread && (
                              <span style={{ width: 8, height: 8, borderRadius: '50%', background: n.accent, flexShrink: 0, display: 'inline-block' }} />
                            )}
                          </div>
                          <p style={{ margin: 0, fontSize: 13 * fs, fontFamily: FF, color: TMC, lineHeight: 1.5 }}>{n.body}</p>
                          {n.scheduledLabel && (
                            <div style={{ display: 'flex', alignItems: 'center', gap: 5, marginTop: 6 }}>
                              <span style={{ fontSize: 11 * fs, fontFamily: FF, color: '#d97706', fontWeight: 700, letterSpacing: '0.01em' }}>
                                🗓 {n.scheduledLabel}
                              </span>
                            </div>
                          )}
                          <span style={{ fontSize: 11 * fs, fontFamily: FF, color: TMC, marginTop: 4, display: 'block' }}>{(() => {
                            if (!n.isoDate) return n.time;
                            const now = new Date(); now.setHours(0,0,0,0);
                            const [_yr, _mo, _dy] = n.isoDate.split('-').map(Number);
                            const due = new Date(_yr, _mo - 1, _dy); due.setHours(0,0,0,0);
                            const d = Math.round((due - now) / 86400000);
                            if (d === 0) return 'Today';
                            if (d === 1) return 'Tomorrow';
                            if (d > 1) return `In ${d} days`;
                            if (d === -1) return '1 day ago';
                            return `${Math.abs(d)} days ago`;
                          })()}</span>
                        </div>
                        <button
                          onClick={e => { e.stopPropagation(); dismiss(n.id); }}
                          style={{ background: 'none', border: 'none', cursor: 'pointer', color: TMC, fontSize: 16 * fs, fontFamily: FF, padding: '0 2px', lineHeight: 1, flexShrink: 0, transition: 'color 0.12s' }}
                          onMouseEnter={e => cs(e).color = '#e74c3c'}
                          onMouseLeave={e => cs(e).color = TMC}
                          title="Delete notification"
                        >✕</button>
                      </div>
                      <div style={{ display: 'flex', gap: 8 }}>
                        {n.unread ? (
                          <button
                            onClick={e => { e.stopPropagation(); markRead(n.id); }}
                            style={{ fontSize: 12 * fs, fontWeight: 600, fontFamily: FF, padding: '4px 12px', borderRadius: 6, cursor: 'pointer', background: ACC, color: BG, border: 'none', transition: 'opacity 0.12s' }}
                            onMouseEnter={e => cs(e).opacity = '0.8'}
                            onMouseLeave={e => cs(e).opacity = '1'}
                          >Mark as read</button>
                        ) : (
                          <button
                            onClick={e => { e.stopPropagation(); markUnread(n.id); }}
                            style={{ fontSize: 12 * fs, fontWeight: 600, fontFamily: FF, padding: '4px 12px', borderRadius: 6, cursor: 'pointer', background: 'none', color: TMC, border: CBR, transition: 'background 0.12s' }}
                            onMouseEnter={e => { cs(e).background = SBG; }}
                            onMouseLeave={e => { cs(e).background = 'none'; }}
                          >Mark as unread</button>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }
  function FavContent({ hoveredApp, setHoveredApp, onShowAll, btnRef, favoritedAppIds, onAppClick }) {
    const containerRef = useRef(null);
    const [boxSize, setBoxSize] = useState(52);
    const fs = useFontScale();

    useEffect(() => {
      const el = containerRef.current;
      if (!el) return;
      const measure = () => {
        const GAP = 10;
        const N = 5;
        const availW = el.offsetWidth;
        const byWidth = (availW - GAP * (N - 1)) / N;
        const parent = el.closest('[data-favcol]');
        const byHeight = parent ? parent.offsetHeight - 18 - 12 - 42 - 12 - 12 : 80;
        setBoxSize(Math.floor(Math.min(byWidth, byHeight, 80)));
      };
      measure();
      const ro = new ResizeObserver(measure);
      ro.observe(el);
      return () => ro.disconnect();
    }, []);

    // Get up to 5 favorited apps; pad remainder with empty slots
    const favApps = (favoritedAppIds || [])
      .slice(0, 5)
      .map(id => APPS.find(a => a.id === id))
      .filter(Boolean);
    const slots = [...favApps, ...Array(5 - favApps.length).fill(null)];

    return (
      <div data-favcol style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
        <div style={{ fontWeight: 700, fontSize: `${18 * fs}px`, letterSpacing: '-0.2px', textAlign: 'center', color: TC }}>
          Apps
        </div>
        <div
          ref={containerRef}
          style={{
            flex: 1,
            display: 'flex', flexDirection: 'column', gap: 0,
            alignItems: 'flex-start', justifyContent: 'center',
            overflow: 'visible',
          }}
        >
          <div style={{ position: 'relative', width: '100%' }}>
            {/* "Favorites" floats above the first softbox, left-aligned to it */}
            <div style={{
              position: 'absolute', bottom: '100%',
              left: `calc(50% - (${5 * boxSize + 4 * 10}px) / 2)`,
              marginBottom: 4,
              fontSize: `${14 * fs}px`, fontWeight: 400,
              fontFamily: FF,
              color: TMC,
              whiteSpace: 'nowrap',
            }}>Favorites</div>
          <div style={{ display: 'flex', gap: '10px', width: '100%', justifyContent: 'center' }}>
          {slots.map((app, i) => (
            <div
              key={i}
              onMouseEnter={() => app && setHoveredApp?.(i)}
              onMouseLeave={() => setHoveredApp?.(null)}
              onClick={() => app && onAppClick && onAppClick(app.id)}
              style={{
                width: boxSize, height: boxSize, flexShrink: 0,
                background: app ? '#1a1a1a' : 'var(--t-restore-bg)',
                borderRadius: '12px', cursor: app ? 'pointer' : 'default',
                position: 'relative',
                border: app ? 'none' : `2px dashed var(--t-card-border)`,
                transition: 'transform 0.16s cubic-bezier(0.34,1.56,0.64,1)',
                transform: hoveredApp === i && app ? 'scale(1.07)' : 'scale(1)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                overflow: 'hidden',
              }}
            >
              {app && (
                <img
                  src={app.icon}
                  alt={app.name}
                  style={{
                    width: '78%', height: '78%',
                    objectFit: 'contain',
                    display: 'block',
                  }}
                />
              )}
              {hoveredApp === i && app && (
                <div style={{
                  position: 'absolute', bottom: 'calc(100% + 6px)', left: '50%',
                  transform: 'translateX(-50%)',
                  background: 'rgba(20,20,20,0.9)', color: '#fff',
                  borderRadius: '8px', padding: '5px 10px',
                  fontSize: `${11 * fs}px`, whiteSpace: 'nowrap',
                  zIndex: 10, textAlign: 'center', lineHeight: 1.4,
                  boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                  animation: 'tooltipIn 0.14s ease',
                }}>
                  {app.name}
                </div>
              )}
            </div>
          ))}
          </div>
          </div>
        </div>
        <button
          ref={btnRef}
          onClick={onShowAll}
          style={{
            width: '100%', padding: '5px 10px',
            background: ACC, color: BG,
            border: 'none', borderRadius: '10px',
            fontWeight: 700, fontSize: `${14 * fs}px`, cursor: 'pointer',
            fontFamily: FF, marginTop: 'auto',
            transition: 'opacity 0.14s, transform 0.12s',
          }}
          onMouseEnter={e => cs(e).opacity = '0.85'}
          onMouseLeave={e => cs(e).opacity = '1'}
          onMouseDown={e  => cs(e).transform   = 'scale(0.97)'}
          onMouseUp={e    => cs(e).transform   = 'scale(1)'}
        >Show All Apps</button>
      </div>
    );
  }
  function NotifContent({ onShowAll, btnRef, notifications, markRead, markUnread, dismiss }) {
    const fs = useFontScale();
    const pinned  = notifications.filter(n => n.pinned);
    const rest    = notifications.filter(n => !n.pinned);
    const visible = [...pinned, ...rest].slice(0, 3);
    return (
      <div style={{ height: '100%', display: 'flex', flexDirection: 'column', gap: 3 }}>
        {/* Notification cards — each gets equal share of remaining height */}
        <div style={{ flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column', gap: 2 }}>
          {visible.map((n, i) => (
            <div key={n.id} style={{
              flex: 1, minHeight: 0,
              display: 'flex', alignItems: 'stretch',
              borderRadius: 7, overflow: 'hidden',
              opacity: n.unread ? 1 : 0.65,
            }}>
              <div style={{ width: 4, flexShrink: 0, background: n.accent }} />
              <div style={{
                flex: 1, minWidth: 0,
                display: 'flex', flexDirection: 'column', justifyContent: 'space-between',
                padding: '3px 7px',
                background: n.unread ? BG : SBG,
              }}>
                {/* Row 1: label + title + dot + dismiss */}
                <div style={{ display: 'flex', alignItems: 'center', gap: 4, minWidth: 0 }}>
                  {n.pinned && <span style={{ fontSize: 7.5 * fs, fontFamily: FF, color: '#d97706', flexShrink: 0 }}>📌</span>}
                  <span style={{
                    fontSize: 7.5 * fs, fontFamily: FF, fontWeight: 800, letterSpacing: '0.06em',
                    color: '#fff', background: n.accent,
                    borderRadius: 3, padding: '1px 4px', flexShrink: 0,
                  }}>{n.label}</span>
                  <span style={{ fontWeight: 700, fontSize: 9.5 * fs, fontFamily: FF, color: TC, flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{n.title}</span>
                  {n.unread && <span style={{ width: 5, height: 5, borderRadius: '50%', background: n.accent, flexShrink: 0 }} />}
                  <button
                    onClick={e => { e.stopPropagation(); dismiss(n.id); }}
                    style={{ background: 'none', border: 'none', cursor: 'pointer', color: TMC, fontSize: 10 * fs, fontFamily: FF, padding: '0 1px', lineHeight: 1, flexShrink: 0, transition: 'color 0.12s' }}
                    onMouseEnter={e => cs(e).color = '#e74c3c'}
                    onMouseLeave={e => cs(e).color = TMC}
                    title="Delete"
                  >✕</button>
                </div>
                {/* Row 2: description */}
                <p style={{ margin: 0, fontSize: 8.5 * fs, fontFamily: FF, color: TMC, lineHeight: 1.3, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{n.body}</p>
                {/* Row 3: mark as read + time */}
                <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
                  {n.unread ? (
                    <button
                      onClick={e => { e.stopPropagation(); markRead(n.id); }}
                      style={{ fontSize: 8 * fs, fontWeight: 600, fontFamily: FF, padding: '1px 5px', borderRadius: 4, cursor: 'pointer', background: ACC, color: BG, border: 'none', transition: 'opacity 0.12s', whiteSpace: 'nowrap' }}
                      onMouseEnter={e => cs(e).opacity = '0.8'}
                      onMouseLeave={e => cs(e).opacity = '1'}
                    >Mark as read</button>
                  ) : (
                    <button
                      onClick={e => { e.stopPropagation(); markUnread(n.id); }}
                      style={{ fontSize: 8 * fs, fontWeight: 600, fontFamily: FF, padding: '1px 5px', borderRadius: 4, cursor: 'pointer', background: 'none', color: TMC, border: `1px solid var(--t-card-border)`, transition: 'background 0.12s', whiteSpace: 'nowrap' }}
                      onMouseEnter={e => cs(e).background = SBG}
                      onMouseLeave={e => cs(e).background = 'none'}
                    >Mark as unread</button>
                  )}
                  <span style={{ fontSize: 8 * fs, fontFamily: FF, color: TMC, marginLeft: 'auto', whiteSpace: 'nowrap' }}>{n.dashTime || n.time}</span>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Show All Notifications button */}
        <button
          ref={btnRef}
          onClick={onShowAll}
          style={{ flexShrink: 0, width: '100%', padding: '5px 10px', background: ACC, color: BG, border: 'none', borderRadius: '10px', fontWeight: 700, fontSize: `${14 * fs}px`, cursor: 'pointer', fontFamily: FF, transition: 'opacity 0.14s, transform 0.12s' }}
          onMouseEnter={e => cs(e).opacity = '0.85'}
          onMouseLeave={e => cs(e).opacity = '1'}
          onMouseDown={e => cs(e).transform = 'scale(0.97)'}
          onMouseUp={e => cs(e).transform = 'scale(1)'}
        >Show All Notifications</button>
      </div>
    );
  }

  function seededRand(seed) {
    let s = seed;
    return () => { s = (s * 16807 + 0) % 2147483647; return (s - 1) / 2147483646; };
  }

  function generateSeries(seed, len, min, max, volatility) {
    const rand = seededRand(seed);
    const pts = [];
    let v = min + rand() * (max - min);
    for (let i = 0; i < len; i++) {
      v = Math.max(min, Math.min(max, v + (rand() - 0.5) * volatility * (max - min)));
      pts.push(parseFloat(v.toFixed(2)));
    }
    return pts;
  }

  const ANALYTICS_GROUPS = [
    {
      name: 'System Health',
      graphs: [
        { name: 'CPU Usage',    unit: '%',    min: 10,  max: 95,   vol: 0.35, seed: 1,  color: '#888888', warnAt: 80  },
        { name: 'Memory Usage', unit: '%',    min: 30,  max: 90,   vol: 0.2,  seed: 2,  color: '#888888', warnAt: 85  },
        { name: 'Disk I/O',     unit: 'MB/s', min: 5,   max: 220,  vol: 0.5,  seed: 3,  color: '#888888', warnAt: null},
      ],
    },
    {
      name: 'Server Status',
      graphs: [
        { name: 'Uptime',        unit: '%',  min: 94,  max: 100, vol: 0.04, seed: 10, color: '#16a34a', warnAt: 95  },
        { name: 'Response Time', unit: 'ms', min: 40,  max: 420, vol: 0.45, seed: 11, color: '#ef4444', warnAt: 300 },
        { name: 'Error Rate',    unit: '%',  min: 0,   max: 8,   vol: 0.4,  seed: 12, color: '#ef4444', warnAt: 5   },
        { name: 'Connections',   unit: '',   min: 80,  max: 600, vol: 0.35, seed: 13, color: '#888888', warnAt: null},
      ],
    },
    {
      name: 'Database Performance',
      graphs: [
        { name: 'Query Latency', unit: 'ms',  min: 2,   max: 180,  vol: 0.5,  seed: 20, color: '#ef4444', warnAt: 120 },
        { name: 'Throughput',    unit: 'qps', min: 200, max: 1200, vol: 0.3,  seed: 21, color: '#888888', warnAt: null},
        { name: 'Cache Hit',     unit: '%',   min: 55,  max: 99,   vol: 0.15, seed: 22, color: '#16a34a', warnAt: 60  },
      ],
    },
    {
      name: 'Bandwidth Throughput',
      graphs: [
        { name: 'Inbound',     unit: 'Mb/s', min: 10, max: 800, vol: 0.45, seed: 30, color: '#888888', warnAt: null},
        { name: 'Outbound',    unit: 'Mb/s', min: 5,  max: 600, vol: 0.4,  seed: 31, color: '#888888', warnAt: null},
        { name: 'Packet Loss', unit: '%',    min: 0,  max: 5,   vol: 0.5,  seed: 32, color: '#ef4444', warnAt: 2   },
      ],
    },
  ];

  const SERIES_LEN = 20;

  // Module-level store — survives any component remount
  const _analyticsSeriesStore = (() => {
    const s = {};
    ANALYTICS_GROUPS.forEach(g => {
      g.graphs.forEach((graph, gi) => {
        s[`${g.name}-${gi}`] = generateSeries(graph.seed, SERIES_LEN, graph.min, graph.max, graph.vol);
      });
    });
    return s;
  })();
  let _analyticsListeners = [];
  setInterval(() => {
    ANALYTICS_GROUPS.forEach(g => {
      g.graphs.forEach((graph, gi) => {
        const key = `${g.name}-${gi}`;
        const arr = _analyticsSeriesStore[key];
        const last = arr[arr.length - 1];
        const delta = (Math.random() - 0.5) * graph.vol * (graph.max - graph.min);
        const nv = Math.max(graph.min, Math.min(graph.max, last + delta));
        _analyticsSeriesStore[key] = [...arr.slice(1), parseFloat(nv.toFixed(2))];
      });
    });
    _analyticsListeners.forEach(fn => fn({ ..._analyticsSeriesStore }));
  }, 2000);

  function Sparkline({ data, color, warnAt, width, height }) {
    if (!data || data.length < 2) return null;
    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;
    const pad = 3;
    const W = Math.max(10, width  || 60);
    const H = Math.max(6,  height || 30);
    const xStep = (W - pad * 2) / (data.length - 1);
    const pts = data.map((v, i) => [
      pad + i * xStep,
      H - pad - ((v - min) / range) * (H - pad * 2),
    ]);
    const polyline = pts.map(([x,y]) => `${x.toFixed(1)},${y.toFixed(1)}`).join(' ');
    const fillPoly = [
      `${pts[0][0].toFixed(1)},${H - pad}`,
      ...pts.map(([x,y]) => `${x.toFixed(1)},${y.toFixed(1)}`),
      `${pts[pts.length-1][0].toFixed(1)},${H - pad}`,
    ].join(' ');
    const last = data[data.length - 1];
    const isWarn = warnAt != null && last >= warnAt;
    const lineColor = isWarn ? '#ef4444' : color;
    const [lx, ly] = pts[pts.length - 1];
    return (
      <svg width={W} height={H} style={{ display: 'block', overflow: 'visible', flexShrink: 0 }}>
        <polygon points={fillPoly} fill={lineColor} fillOpacity={0.18} />
        <polyline points={polyline} fill="none" stroke={lineColor} strokeWidth="1.6" strokeLinejoin="round" strokeLinecap="round" />
        <circle cx={lx} cy={ly} r="2.4" fill={lineColor} />
        {warnAt != null && (() => {
          const wy = H - pad - ((warnAt - min) / range) * (H - pad * 2);
          if (wy < pad || wy > H - pad) return null;
          return <line x1={pad} y1={wy} x2={W-pad} y2={wy} stroke="#ef4444" strokeWidth="1" strokeDasharray="3,2" opacity="0.35" />;
        })()}
      </svg>
    );
  }

  // LABEL_H: pixels consumed by name label + value label above/below sparkline
  const LABEL_H = 22; // ~11px name + ~11px value

  function GraphCell({ graph, seriesData, width, height }) {
    const fs = useFontScale();
    const last = seriesData.length ? seriesData[seriesData.length - 1] : 0;
    const isWarn = graph.warnAt != null && last >= graph.warnAt;
    const sparkH = Math.max(6, height - LABEL_H - 4); // 4px for bg padding
    const trend  = getTrend(seriesData);
    const color  = trendColor(trend);
    return (
      <div style={{
        display: 'flex', flexDirection: 'column', alignItems: 'flex-start',
        width, minWidth: 0, height, overflow: 'hidden', flexShrink: 0,
        background: 'var(--t-restore-bg)', borderRadius: 6, padding: '2px 3px',
        boxSizing: 'border-box',
      }}>
        <div style={{ fontSize: 8.5 * fs, fontFamily: FF, fontWeight: 600, color: TMC, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', width: '100%', lineHeight: '11px', flexShrink: 0 }}>
          {graph.name}
        </div>
        <Sparkline data={seriesData} color={color} warnAt={graph.warnAt} width={width - 6} height={sparkH} />
        <div style={{ fontSize: 8.5 * fs, fontFamily: FF, fontWeight: 700, color: isWarn ? '#ef4444' : color, lineHeight: '11px', flexShrink: 0 }}>
          {last % 1 === 0 ? last : last.toFixed(1)}{graph.unit}
        </div>
      </div>
    );
  }

  function AnalyticsGroup({ group, allSeries, groupW, groupH, isLast }) {
    const fs = useFontScale();
    const count  = group.graphs.length;
    // Header takes ~22px (10px text + 5px border/margin + 7px gap)
    const HEADER_H = 22;
    const innerW = Math.max(10, groupW - 14);
    const innerH = Math.max(10, groupH - HEADER_H);

    // leftW/rightW split for 3-4 graph groups
    const leftW  = count >= 3 ? Math.floor(innerW * 0.52) : innerW;
    const rightW = count >= 3 ? Math.max(1, innerW - leftW - 4) : 0;

    // Height calculations
    const singleH = innerH;
    const stackH  = (n) => Math.floor((innerH - (n - 1) * 3) / n);

    const renderCell = (gi, w, h) => {
      const g    = group.graphs[gi];
      const data = allSeries[`${group.name}-${gi}`] || [];
      return <GraphCell key={gi} graph={g} seriesData={data} width={w} height={h} />;
    };

    const renderVStack = (indices, colW) => (
      <div style={{ display: 'flex', flexDirection: 'column', gap: 3, height: innerH, flexShrink: 0 }}>
        {indices.map(gi => renderCell(gi, colW, stackH(indices.length)))}
      </div>
    );

    return (
      <div style={{
        display: 'flex', flexDirection: 'column', flex: 1, minWidth: 0,
        padding: '0 7px',
        borderRight: isLast ? 'none' : CBR,
        overflow: 'hidden',
      }}>
        {/* Group header */}
        <div style={{
          fontSize: 9.5 * fs, fontFamily: FF, fontWeight: 800, color: TC,
          textTransform: 'uppercase', letterSpacing: '0.04em',
          textAlign: 'center', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
          borderBottom: '2px solid var(--t-accent)', paddingBottom: 3, marginBottom: 4, lineHeight: '13px',
          flexShrink: 0,
        }}>{group.name}</div>

        {/* Graph body */}
        <div style={{ display: 'flex', gap: 4, overflow: 'hidden', height: innerH, flexShrink: 0 }}>

          {/* 1 graph: full width, full height */}
          {count === 1 && renderCell(0, innerW, singleH)}

          {/* 2 graphs: stacked vertically */}
          {count === 2 && renderVStack([0, 1], innerW)}

          {/* 3-4 graphs: big left + right column stack */}
          {count >= 3 && (
            <>
              <div style={{ flexShrink: 0 }}>{renderCell(0, leftW, singleH)}</div>
              {renderVStack(group.graphs.slice(1).map((_, i) => i + 1), rightW)}
            </>
          )}

        </div>
      </div>
    );
  }

  function AnalyticsContent({ onSeeAll, btnRef }) {
    const containerRef = useRef(null);
    const [dims, setDims] = useState({ w: 500, h: 160 });
    const [series, setSeries] = useState(() => ({ ..._analyticsSeriesStore }));
    const fs = useFontScale();

    useEffect(() => {
      const listener = s => setSeries(s);
      _analyticsListeners.push(listener);
      return () => { _analyticsListeners = _analyticsListeners.filter(f => f !== listener); };
    }, []);

    useEffect(() => {
      const el = containerRef.current; if (!el) return;
      const measure = () => setDims({ w: el.offsetWidth, h: el.offsetHeight });
      const ro = new ResizeObserver(measure);
      ro.observe(el); measure();
      return () => ro.disconnect();
    }, []);

    const BTN_H = 28; // height reserved for the See All button + gap
    const groupW = Math.floor(dims.w / ANALYTICS_GROUPS.length);

    return (
      <div ref={containerRef} style={{ display: 'flex', flexDirection: 'column', width: '100%', height: '100%', overflow: 'hidden', gap: 8 }}>
        {/* Groups row */}
        <div style={{ display: 'flex', flex: 1, minHeight: 0, overflow: 'hidden' }}>
          {ANALYTICS_GROUPS.map((group, i) => (
            <AnalyticsGroup
              key={i}
              group={group}
              allSeries={series}
              groupW={groupW}
              groupH={dims.h - BTN_H - 8}
              isLast={i === ANALYTICS_GROUPS.length - 1}
            />
          ))}
        </div>

        {/* See All button */}
        <button
          ref={btnRef}
          onClick={onSeeAll}
          style={{
            flexShrink: 0,
            width: '100%', padding: '5px 10px',
            background: ACC, color: BG,
            border: 'none', borderRadius: '10px',
            fontWeight: 700, fontSize: `${14 * fs}px`, cursor: 'pointer',
            fontFamily: FF,
            transition: 'opacity 0.14s, transform 0.12s',
          }}
          onMouseEnter={e => cs(e).opacity = '0.85'}
          onMouseLeave={e => cs(e).opacity = '1'}
          onMouseDown={e  => cs(e).transform   = 'scale(0.97)'}
          onMouseUp={e    => cs(e).transform   = 'scale(1)'}
        >See All</button>
      </div>
    );
  }

  // Per-graph background palette — cycles through these
  // Card background is always gray; line/accent color is determined by trend
  function getTrend(data) {
    if (!data || data.length < 11) return 'neutral';
    const recent = data.slice(-10);
    const prior  = data.slice(-20, -10);
    if (prior.length < 10) return 'neutral';
    const avgRecent = recent.reduce((a, b) => a + b, 0) / recent.length;
    const avgPrior  = prior.reduce((a, b) => a + b, 0) / prior.length;
    const diff = avgRecent - avgPrior;
    if (diff >= 5)  return 'up';
    if (diff <= -5) return 'down';
    return 'neutral';
  }
  function trendColor(trend) {
    if (trend === 'up')   return '#16a34a'; // green
    if (trend === 'down') return '#ef4444'; // red
    return '#888888';                        // gray neutral
  }
  function trendBorder(trend) {
    if (trend === 'up')   return '#86efac';
    if (trend === 'down') return '#fca5a5';
    return '#cccccc';
  }

  function AnalyticsOverlay({ phase, onClose }) {
    const panelRef  = useRef(null);
    const fs = useFontScale();
    const [search, setSearch] = useState('');
    const [series, setSeries] = useState(() => ({ ..._analyticsSeriesStore }));

    useEffect(() => {
      const listener = s => setSeries(s);
      _analyticsListeners.push(listener);
      return () => { _analyticsListeners = _analyticsListeners.filter(f => f !== listener); };
    }, []);

    useEffect(() => {
      const el = panelRef.current; if (!el) return;
      const o = window.__analyticsOrigin; if (!o) return;
      el.style.transformOrigin = `${o.ox} ${o.oy}`;
      el.style.setProperty('--scale-from', `scale(${o.sx}, ${o.sy})`);
    });

    if (phase === 'hidden') return null;

    const q = search.toLowerCase().trim();

    // Flatten all graphs with their group info for searching
    let _unused = 0;
    const filteredGroups = ANALYTICS_GROUPS.map(group => ({
      ...group,
      graphs: group.graphs.filter(g =>
        !q || g.name.toLowerCase().includes(q) || group.name.toLowerCase().includes(q)
      ),
    })).filter(g => g.graphs.length > 0);

    return (
      <div className={`apps-panel ${phase}`} ref={panelRef}>
        <div className="apps-inner">
          {/* Sticky header */}
          <div className="apps-header">
            <APGLogo />
            <div className="apps-logo">ANALYTICS</div>
            <input
              className="apps-search"
              type="text"
              placeholder="Search graphs..."
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
            <button className="apps-close-btn" onClick={onClose}>✕</button>
          </div>

          {/* Groups */}
          {filteredGroups.length === 0 ? (
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: 200, color: TMC, fontSize: 16, fontWeight: 600 }}>
              No graphs found
            </div>
          ) : filteredGroups.map((group) => (
            <div key={group.name} style={{ marginBottom: 40 }}>
              {/* Group name */}
              <div style={{
                fontSize: 22 * fs, fontWeight: 900, fontFamily: FF, color: TC,
                letterSpacing: '-0.3px', marginBottom: 16,
                paddingBottom: 10, borderBottom: '2.5px solid var(--t-accent)',
              }}>{group.name}</div>

              {/* Graph cards grid */}
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))',
                gap: 16,
              }}>
                {group.graphs.map((graph, gi) => {
                  // Find the original group to get the correct index
                  const origGroup = ANALYTICS_GROUPS.find(g => g.name === group.name);
                  const origIdx = origGroup ? origGroup.graphs.indexOf(graph) : gi;
                  const key   = `${group.name}-${origIdx}`;
                  const data  = (series && series[key]) || [];
                  const last  = data.length ? data[data.length - 1] : 0;
                  const isWarn = graph.warnAt != null && last >= graph.warnAt;
                  const trend  = getTrend(data);
                  const lineColor = trendColor(trend);
                  const borderCol = trendBorder(trend);

                  // Full-size sparkline
                  const sparkData = data;
                  const W = 240, H = 120, pad = 8;
                  const sMin = sparkData.length ? Math.min(...sparkData) : 0;
                  const sMax = sparkData.length ? Math.max(...sparkData) : 1;
                  const sRange = sMax - sMin || 1;
                  const xStep = sparkData.length > 1 ? (W - pad*2) / (sparkData.length - 1) : 0;
                  const pts = sparkData.map((v, i) => [
                    pad + i * xStep,
                    H - pad - ((v - sMin) / sRange) * (H - pad*2),
                  ]);
                  const polyline = pts.map(([x,y]) => `${x.toFixed(1)},${y.toFixed(1)}`).join(' ');
                  const fillPoly = pts.length > 1 ? [
                    `${pts[0][0].toFixed(1)},${H-pad}`,
                    ...pts.map(([x,y]) => `${x.toFixed(1)},${y.toFixed(1)}`),
                    `${pts[pts.length-1][0].toFixed(1)},${H-pad}`,
                  ].join(' ') : '';
                  const [lx, ly] = pts.length ? pts[pts.length-1] : [0,0];

                  return (
                    <div key={graph.name} style={{
                      background: 'var(--t-restore-bg)',
                      borderRadius: 14,
                      padding: '16px 18px 14px',
                      border: `1.5px solid ${borderCol}`,
                      display: 'flex', flexDirection: 'column', gap: 8,
                    }}>
                      {/* Card header */}
                      <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' }}>
                        <div>
                          <div style={{ fontSize: 13 * fs, fontWeight: 700, color: TMC, marginBottom: 2 }}>{graph.name}</div>
                          <div style={{
                            fontSize: 26 * fs, fontWeight: 800, fontFamily: FF, color: isWarn ? '#ef4444' : TC,
                            lineHeight: 1,
                          }}>
                            {typeof last === 'number' ? (last % 1 === 0 ? last : last.toFixed(1)) : '—'}{graph.unit}
                          </div>
                        </div>
                        {isWarn && (
                          <span style={{ fontSize: 10, fontFamily: FF, fontWeight: 700, color: '#ef4444', background: '#fee2e2', border: '1px solid #fca5a5', borderRadius: 6, padding: '3px 8px' }}>
                            ⚠ HIGH
                          </span>
                        )}
                        {!isWarn && graph.warnAt != null && (
                          <span style={{ fontSize: 10, fontFamily: FF, fontWeight: 600, color: '#16a34a', background: '#dcfce7', border: '1px solid #86efac', borderRadius: 6, padding: '3px 8px' }}>
                            ✓ OK
                          </span>
                        )}
                      </div>

                      {/* Sparkline */}
                      {sparkData.length > 1 && (
                        <svg width="100%" viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none" style={{ display: 'block', height: 100 }}>
                          {fillPoly && <polygon points={fillPoly} fill={lineColor} fillOpacity={0.18} />}
                          <polyline points={polyline} fill="none" stroke={lineColor} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" />
                          <circle cx={lx} cy={ly} r="4" fill={lineColor} />
                          {graph.warnAt != null && (() => {
                            const wy = H - pad - ((graph.warnAt - sMin) / sRange) * (H - pad*2);
                            if (wy < pad || wy > H - pad) return null;
                            return <line x1={pad} y1={wy} x2={W-pad} y2={wy} stroke="#ef4444" strokeWidth="1.5" strokeDasharray="5,3" opacity="0.5" />;
                          })()}
                        </svg>
                      )}

                      {/* Stats row */}
                      <div style={{ display: 'flex', gap: 12, fontSize: 11, color: TMC }}>
                        <span>Min <strong style={{ color: TC }}>{sparkData.length ? Math.min(...sparkData).toFixed(1) : '—'}{graph.unit}</strong></span>
                        <span>Max <strong style={{ color: TC }}>{sparkData.length ? Math.max(...sparkData).toFixed(1) : '—'}{graph.unit}</strong></span>
                        {graph.warnAt != null && (
                          <span style={{ marginLeft: 'auto' }}>Threshold <strong style={{ color: '#ef4444' }}>{graph.warnAt}{graph.unit}</strong></span>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }
  function TutorialsContent({ onLearnMore }) {
    const fs = useFontScale();
    return (
      <div style={{
        height: '100%', display: 'flex', flexDirection: 'column',
        alignItems: 'center', justifyContent: 'space-between',
        padding: '4px 0 0', overflow: 'hidden',
      }}>
        {/* Top: title + description + icon — compresses when tile shrinks */}
        <div style={{
          display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6,
          flex: 1, minHeight: 0, overflow: 'hidden', justifyContent: 'center',
          width: '100%',
        }}>

          <p style={{
            margin: 0, fontSize: 10 * fs, color: TMC,
            textAlign: 'center', lineHeight: 1.55,
            maxWidth: 200, flexShrink: 1,
            overflow: 'hidden',
          }}>
            Learn more about how to use our services, this includes documentation, videos, or forums!
          </p>

          {/* Graduation cap SVG — shrinks with available space */}
          <svg viewBox="0 0 120 90" style={{ width: '60%', maxWidth: 110, height: 'auto', minHeight: 0, flexShrink: 1, marginTop: 4 }} fill="none" xmlns="http://www.w3.org/2000/svg">
            <polygon points="60,10 110,32 60,54 10,32" fill="none" stroke="var(--t-accent)" strokeWidth="3.5" strokeLinejoin="round" />
            <path d="M28,40 L28,62 Q60,76 92,62 L92,40" fill="none" stroke="var(--t-accent)" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round" />
            <line x1="110" y1="32" x2="110" y2="58" stroke="var(--t-accent)" strokeWidth="3.5" strokeLinecap="round" />
            <line x1="110" y1="58" x2="106" y2="72" stroke="var(--t-accent)" strokeWidth="3" strokeLinecap="round" />
            <line x1="110" y1="58" x2="110" y2="72" stroke="var(--t-accent)" strokeWidth="3" strokeLinecap="round" />
            <line x1="110" y1="58" x2="114" y2="72" stroke="var(--t-accent)" strokeWidth="3" strokeLinecap="round" />
            <circle cx="110" cy="74" r="3" fill="var(--t-accent)" />
          </svg>
        </div>

        {/* Button — always pinned to bottom, never pushed out */}
        <button onClick={onLearnMore} style={{
          flexShrink: 0,
          width: '100%', padding: '9px 10px',
          background: ACC, color: BG,
          border: 'none', borderRadius: '10px',
          fontWeight: 700, fontSize: `${14 * fs}px`,
          cursor: 'pointer',
          fontFamily: FF,
          transition: 'opacity 0.14s, transform 0.12s',
        }}
          onMouseEnter={e => cs(e).opacity = '0.85'}
          onMouseLeave={e => cs(e).opacity = '1'}
          onMouseDown={e => cs(e).transform = 'scale(0.97)'}
          onMouseUp={e => cs(e).transform = 'scale(1)'}
        >Learn More</button>
      </div>
    );
  }
  function AppTutorialPage({ app, onBack }) {
    const [activeSection, setActiveSection] = useState('docs');
    const [sidebarHovered, setSidebarHovered] = useState(false);
    const fs = useFontScale();
    const docsRef   = useRef(null);
    const videosRef = useRef(null);
    const forumsRef = useRef(null);
    const scrollRef = useRef(null);

    // Update active section based on scroll position
    useEffect(() => {
      const el = scrollRef.current; if (!el) return;
      const onScroll = () => {
        // Use offsetTop relative to the scroll container for reliable detection
        const scrollTop = el.scrollTop;
        const OFFSET = 40; // px from top before activating next section

        const sections = [
          { id: 'docs',   ref: docsRef   },
          { id: 'videos', ref: videosRef },
          { id: 'forums', ref: forumsRef },
        ];

        let active = 'docs';
        for (const { id, ref } of sections) {
          if (!ref.current) continue;
          // offsetTop gives position relative to offsetParent (scroll container)
          const sectionTop = ref.current.offsetTop - OFFSET;
          if (scrollTop >= sectionTop) active = id;
        }
        setActiveSection(active);
      };
      el.addEventListener('scroll', onScroll, { passive: true });
      // Run once on mount to set initial state
      onScroll();
      return () => el.removeEventListener('scroll', onScroll);
    }, []);

    const scrollTo = (ref, id) => {
      setActiveSection(id);
      ref.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    };

    const NAV = [
      { id: 'docs',   label: 'Documentation', ref: docsRef,
        icon: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><line x1="10" y1="9" x2="8" y2="9"/><path d="M12 18l2-2-2-2" strokeWidth="1.5"/></svg> },
      { id: 'videos', label: 'Videos', ref: videosRef,
        icon: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><polygon points="10 8 16 12 10 16 10 8" fill="currentColor" stroke="none"/></svg> },
      { id: 'forums', label: 'Forums to refer to', ref: forumsRef,
        icon: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/><line x1="8" y1="10" x2="8.01" y2="10" strokeWidth="3"/><line x1="12" y1="10" x2="12.01" y2="10" strokeWidth="3"/><line x1="16" y1="10" x2="16.01" y2="10" strokeWidth="3"/></svg> },
    ];

    const SIDEBAR_W_COLLAPSED = 96;
    const SIDEBAR_W_EXPANDED  = 220;
    const sidebarW = sidebarHovered ? SIDEBAR_W_EXPANDED : SIDEBAR_W_COLLAPSED;

    // Forum sites
    const FORUMS = [
      { name: 'Reddit',        desc: `Reddit has topics related to this app that can help you learn more about ${app.name}.`,        color: '#ff4500', icon: <svg width="28" height="28" viewBox="0 0 24 24" fill="#ff4500"><circle cx="12" cy="12" r="12" fill="#ff4500"/><path d="M19.99 12a2 2 0 0 0-3.36-1.46 9.8 9.8 0 0 0-5.27-1.67l.9-4.22 2.9.62a1.4 1.4 0 1 0 .14-.66l-3.24-.7a.25.25 0 0 0-.3.19l-1 4.72a9.84 9.84 0 0 0-5.31 1.72 2 2 0 1 0-2.22 3.24 3.94 3.94 0 0 0 0 .5c0 2.56 2.98 4.63 6.65 4.63s6.65-2.07 6.65-4.63a3.94 3.94 0 0 0 0-.5 2 2 0 0 0 1.16-1.78zM8.5 13a1 1 0 1 1 1 1 1 1 0 0 1-1-1zm5.6 2.64a3.47 3.47 0 0 1-2.1.58 3.47 3.47 0 0 1-2.1-.58.25.25 0 0 1 .35-.35 3 3 0 0 0 1.75.43 3 3 0 0 0 1.75-.43.25.25 0 0 1 .35.35zm-.1-1.64a1 1 0 1 1 1-1 1 1 0 0 1-1 1z" fill="#fff"/></svg> },
      { name: 'StackOverflow', desc: `StackOverflow has topics related to this app that can help you learn more about ${app.name}.`, color: '#f48024', icon: <svg width="28" height="28" viewBox="0 0 24 24"><rect width="24" height="24" rx="3" fill="#fff"/><path d="M17.5 18.5v-4h1.5V20h-13v-5.5H7.5v4h10zM9 15.5l.3-1.5 6.3 1.3-.3 1.5L9 15.5zm1-3.2.6-1.4 5.8 2.5-.6 1.4-5.8-2.5zm1.8-3l1-1.2 4.8 3.6-1 1.2-4.8-3.6zm3.2-3.3 3.5 4.7-1.2.9-3.5-4.7 1.2-.9zM9 18.5v-1.5h6.5v1.5H9z" fill="#f48024"/></svg> },
      { name: 'Dev.to',        desc: `Dev.to has topics related to this app that can help you learn more about ${app.name}.`,        color: '#0a0a0a', icon: <svg width="28" height="28" viewBox="0 0 24 24"><rect width="24" height="24" rx="3" fill="#0a0a0a"/><text x="2" y="17" fontSize="9" fontWeight="900" fill="#fff" fontFamily="monospace">DEV</text></svg> },
    ];

    return (
      <div style={{
        position: 'fixed', inset: 0, zIndex: 700,
        display: 'flex', background: 'var(--t-bg)',
        left: 0,
      }}>
<div
          onMouseEnter={() => setSidebarHovered(true)}
          onMouseLeave={() => setSidebarHovered(false)}
          style={{
            width: sidebarW, flexShrink: 0,
            background: SBG,
            borderRight: CBR,
            display: 'flex', flexDirection: 'column',
            overflow: 'hidden',
            transition: 'width 0.22s cubic-bezier(0.4,0,0.2,1)',
          }}
        >
          {/* Logo header */}
          <div style={{
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            padding: '12px 10px',
            borderBottom: CBR,
            flexShrink: 0,
            minHeight: sidebarHovered ? 72 : 56,
            transition: 'min-height 0.22s cubic-bezier(0.4,0,0.2,1)',
            overflow: 'hidden',
          }}>
            <APGLogo collapsed={!sidebarHovered} />
          </div>

          {/* App header */}
          <div style={{
            display: 'flex', alignItems: 'center', gap: 10,
            padding: '14px 10px',
            borderBottom: CBR,
            flexShrink: 0, minHeight: 60,
          }}>
            <div style={{
              width: 40, height: 40, borderRadius: 10, flexShrink: 0,
              background: '#1a1a1a',
              backgroundImage: `url(${app.icon})`,
              backgroundSize: 'cover', backgroundPosition: 'center',
            }} />
            {sidebarHovered && (
              <span style={{ fontWeight: 800, fontSize: 15, color: TC, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                {app.name}
              </span>
            )}
          </div>

          {/* Nav items */}
          {NAV.map(item => {
            const isActive = activeSection === item.id;
            return (
              <button
                key={item.id}
                onClick={() => scrollTo(item.ref, item.id)}
                style={{
                  display: 'flex', alignItems: 'center', gap: 12,
                  padding: '18px 14px',
                  paddingLeft: isActive ? 11 : 14,
                  background: isActive ? BG : 'none',
                  border: 'none',
                  borderBottom: CBR,
                  borderLeft: isActive ? `3px solid var(--t-accent)` : '3px solid transparent',
                  cursor: 'pointer', fontFamily: FF,
                  color: isActive ? ACC : TC,
                  textAlign: 'left',
                  transition: 'background 0.15s, border-left 0.15s, color 0.15s',
                  whiteSpace: 'nowrap', overflow: 'hidden',
                  width: '100%',
                  boxSizing: 'border-box',
                }}
                onMouseEnter={e => { if (!isActive) cs(e).background = BG; }}
                onMouseLeave={e => { if (!isActive) cs(e).background = 'none'; }}
              >
                <span style={{ flexShrink: 0, color: isActive ? ACC : TMC, transition: 'color 0.15s' }}>{item.icon}</span>
                {sidebarHovered && (
                  <span style={{ fontSize: 14, fontWeight: isActive ? 700 : 500, overflow: 'hidden', textOverflow: 'ellipsis' }}>
                    {item.label}
                  </span>
                )}
              </button>
            );
          })}

          {/* Back button at bottom */}
          <div style={{ marginTop: 'auto', padding: 10, borderTop: CBR }}>
            <button
              onClick={onBack}
              style={{
                width: '100%', padding: '8px 0',
                background: ACC, color: BG,
                border: 'none', borderRadius: 8,
                fontWeight: 700, fontSize: 12,
                cursor: 'pointer', fontFamily: FF,
                transition: 'opacity 0.12s',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
              }}
              onMouseEnter={e=>cs(e).opacity='0.8'} onMouseLeave={e=>cs(e).opacity='1'}
            >
              <span>←</span>
              {sidebarHovered && <span>Back</span>}
            </button>
          </div>
        </div>
<div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: `32px 32px ${(app.id === 'admin' || app.id === 'rdaDeployer') ? '600px' : '375px'}`, background: 'var(--t-bg)' }}>

          {/* Documentation section */}
          <div ref={docsRef} style={{ marginBottom: 56 }}>
            <h2 style={{ fontSize: 34 * fs, fontWeight: 300, margin: '0 0 18px', letterSpacing: '-0.5px', color: TC }}>Documentation</h2>
            <p style={{ fontSize: 14 * fs, color: TMC, lineHeight: 1.75, margin: '0 0 16px', maxWidth: 680 }}>
              Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id est laborum
            </p>
            <p style={{ fontSize: 13 * fs, color: TMC, lineHeight: 1.7, margin: 0, maxWidth: 680 }}>
              <strong style={{ color: TC }}>BEFORE USING, IT IS IMPORTANT TO NOTE THAT:</strong> Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat.
            </p>
          </div>

          {/* Videos section */}
          <div ref={videosRef} style={{ marginBottom: 56 }}>
            <h2 style={{ fontSize: 34 * fs, fontWeight: 300, margin: '0 0 20px', letterSpacing: '-0.5px', color: TC }}>Videos</h2>
            {[0, 1].map(i => (
              <div key={i} style={{
                width: '100%', maxWidth: 480,
                aspectRatio: '16/9',
                background: 'var(--t-restore-bg)',
                borderRadius: 8,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                marginBottom: 20,
              }}>
                <div style={{
                  width: 60, height: 60, borderRadius: '50%',
                  border: `3px solid var(--t-card-border)`,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  background: 'rgba(128,128,128,0.15)',
                }}>
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="var(--t-text-muted)">
                    <polygon points="8 5 19 12 8 19 8 5"/>
                  </svg>
                </div>
              </div>
            ))}
          </div>

          {/* Forums section */}
          <div ref={forumsRef}>
            <h2 style={{ fontSize: 34 * fs, fontWeight: 300, margin: '0 0 20px', letterSpacing: '-0.5px', color: TC }}>Forums to refer to</h2>
            {(app.id === 'admin' || app.id === 'rdaDeployer') ? (
              <p style={{
                fontSize: 32 * fs, fontStyle: 'italic',
                color: TMC, opacity: 0.5,
                margin: 0, lineHeight: 1.4, fontWeight: 400,
              }}>This app is unavailable to the public.</p>
            ) : (
              FORUMS.map(forum => (
                <div key={forum.name} style={{
                  display: 'flex', alignItems: 'center', gap: 16,
                  marginBottom: 20, paddingBottom: 20,
                  borderBottom: `1px solid var(--t-card-border)`,
                }}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: 700, fontSize: 16 * fs, color: TC, marginBottom: 4 }}>{forum.name}</div>
                    <div style={{ fontSize: 13 * fs, color: TMC, lineHeight: 1.5, maxWidth: 340 }}>{forum.desc}</div>
                  </div>
                  <button style={{
                    flexShrink: 0, padding: '8px 18px',
                    background: ACC, color: BG,
                    border: 'none', borderRadius: 8,
                    fontWeight: 700, fontSize: 13 * fs, cursor: 'pointer',
                    fontFamily: FF, transition: 'opacity 0.12s',
                    whiteSpace: 'nowrap',
                  }}
                    onMouseEnter={e => cs(e).opacity = '0.8'}
                    onMouseLeave={e => cs(e).opacity = '1'}
                  >Click Here</button>
                  <div style={{ width: 40, height: 40, flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    {forum.icon}
                  </div>
                </div>
              ))
            )}
          </div>

        </div>
      </div>
    );
  }

  function TutorialsOverlay({ onClose }) {
    const [query, setQuery]           = useState('');
    const [showSearch, setShowSearch] = useState(false);
    const fs = useFontScale();
    const [dropOpen, setDropOpen]     = useState(false);
    const [selectedApp, setSelectedApp] = useState(null);
    const [dropMaxH, setDropMaxH]     = useState(260);
    // 'search' | 'exiting-to-app' | 'app' | 'exiting-to-search'
    const [phase, setPhase]           = useState('search');
    const [pendingApp, setPendingApp] = useState(null);
    const inputRef   = useRef(null);
    const searchWrap = useRef(null);

    // Stagger: search bar fades in 700ms after mount
    useEffect(() => {
      const t = setTimeout(() => setShowSearch(true), 700);
      return () => clearTimeout(t);
    }, []);

    // Auto-focus and open dropdown once search bar appears
    useEffect(() => {
      if (showSearch && phase === 'search') {
        const t = setTimeout(() => {
          inputRef.current?.focus();
          setDropOpen(true);
        }, 50);
        return () => clearTimeout(t);
      }
    }, [showSearch, phase]);

    // Recalculate dropdown max height
    useEffect(() => {
      if (!dropOpen || !searchWrap.current) return;
      const rect = searchWrap.current.getBoundingClientRect();
      const available = window.innerHeight - rect.bottom - 6 - 80;
      setDropMaxH(Math.max(80, available));
    }, [dropOpen]);

    // Navigate to app — play exit then show app page
    const goToApp = (app) => {
      setPendingApp(app);
      setPhase('exiting-to-app');
      setTimeout(() => {
        setSelectedApp(app);
        setPhase('app');
      }, 320);
    };

    // Navigate back — play exit then show search
    const goBack = () => {
      setPhase('exiting-to-search');
      setTimeout(() => {
        setSelectedApp(null);
        setPendingApp(null);
        setPhase('search');
      }, 300);
    };

    const q = query.toLowerCase().trim();
    const matchedApps = q
      ? APPS.filter(a => a.name.toLowerCase().includes(q)).sort((a,b) => a.name.localeCompare(b.name))
      : [...APPS].sort((a,b) => a.name.localeCompare(b.name));
    const grouped = {};
    matchedApps.forEach(app => {
      const letter = app.name[0].toUpperCase();
      if (!grouped[letter]) grouped[letter] = [];
      grouped[letter].push(app);
    });
    const groupEntries = Object.entries(grouped).sort(([a],[b]) => a.localeCompare(b));

    // Determine animation for the active view
    const searchAnim = phase === 'exiting-to-app'
      ? 'tutPageExit 0.32s cubic-bezier(0.4,0,0.2,1) both'
      : phase === 'search' && selectedApp === null
        ? 'tutPageBack 0.38s cubic-bezier(0.22,1,0.36,1) both'
        : 'none';

    const appAnim = phase === 'app'
      ? 'tutPageEnter 0.4s cubic-bezier(0.22,1,0.36,1) both'
      : phase === 'exiting-to-search'
        ? 'tutPageExit 0.3s cubic-bezier(0.4,0,0.2,1) both'
        : 'none';

    return (
      <div style={{
        position: 'fixed', inset: 0, zIndex: 600,
        background: 'var(--t-bg)', left: 96,
        overflow: 'hidden',
      }}>
{(phase === 'app' || phase === 'exiting-to-search') && selectedApp && (
          <div style={{ animation: appAnim, width: '100%', height: '100%' }}>
            <AppTutorialPage app={selectedApp} onBack={goBack} />
          </div>
        )}
{(phase === 'search' || phase === 'exiting-to-app') && (
          <div style={{
            animation: searchAnim,
            position: 'absolute', inset: 0,
            display: 'flex', flexDirection: 'column',
            alignItems: 'center', justifyContent: 'flex-start',
            paddingTop: '12vh',
            background: 'var(--t-bg)',
          }}>
            {/* APG Logo top-left */}
            <div style={{ position: 'absolute', top: 18, left: 24 }}>
              <APGLogo />
            </div>

            {/* Close button */}
            <button
              onClick={onClose}
              style={{
                position: 'absolute', top: 20, right: 24,
                width: 36, height: 36, borderRadius: '50%',
                border: CBR, background: SBG,
                cursor: 'pointer', fontSize: 16, color: TC,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                transition: 'background 0.14s, transform 0.14s',
              }}
              onMouseEnter={e => { cs(e).background='var(--t-restore-bg)'; cs(e).transform='scale(1.1)'; }}
              onMouseLeave={e => { cs(e).background=SBG; cs(e).transform='scale(1)'; }}
            >✕</button>

            {/* Tutorials label */}
            <div style={{
              fontSize: 26 * fs, fontWeight: 900, fontFamily: FF,
              border: `3px solid var(--t-accent)`, borderRadius: 14,
              padding: '4px 20px', lineHeight: 1.25,
              marginBottom: 32, color: TC,
              animation: phase === 'search' && !selectedApp ? 'tutFadeSlideIn 0.5s cubic-bezier(0.22,1,0.36,1) both' : 'none',
            }}>Tutorials</div>

            {/* Subtitle */}
            <div style={{
              textAlign: 'center', marginBottom: 28,
              animation: phase === 'search' && !selectedApp ? 'tutFadeSlideIn 0.5s cubic-bezier(0.22,1,0.36,1) 0.1s both' : 'none',
            }}>
              <div style={{ fontSize: 20 * fs, fontWeight: 600, color: TC, lineHeight: 1.4 }}>
                What app do you need help with?
              </div>
            </div>

            {/* Search bar */}
            {showSearch && (
              <div ref={searchWrap} style={{
                position: 'relative', width: '100%', maxWidth: 380,
                animation: phase === 'search' && !selectedApp ? 'tutSearchIn 0.45s cubic-bezier(0.22,1,0.36,1) both' : 'none',
              }}>
                <div style={{
                  display: 'flex', alignItems: 'center',
                  border: CBR, borderRadius: 50,
                  background: SBG, padding: '10px 16px',
                  boxShadow: dropOpen ? '0 2px 12px rgba(0,0,0,0.1)' : 'none',
                  transition: 'box-shadow 0.15s',
                }}>
                  <input
                    ref={inputRef}
                    type="text"
                    placeholder="Search..."
                    value={query}
                    onChange={e => { setQuery(e.target.value); setDropOpen(true); }}
                    onFocus={() => setDropOpen(true)}
                    style={{
                      flex: 1, border: 'none', outline: 'none',
                      fontSize: 15, fontFamily: FF, background: 'transparent',
                      color: TC,
                    }}
                  />
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="var(--t-text-muted)" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                    <circle cx="11" cy="11" r="7"/><line x1="16.5" y1="16.5" x2="22" y2="22"/>
                  </svg>
                </div>

                {/* Dropdown */}
                {dropOpen && matchedApps.length > 0 && (
                  <div style={{
                    position: 'absolute', top: 'calc(100% + 6px)', left: 0, right: 0,
                    background: BG, border: CBR,
                    borderRadius: 14, overflow: 'hidden',
                    boxShadow: '0 8px 28px rgba(0,0,0,0.12)',
                    maxHeight: dropMaxH, overflowY: 'auto',
                    animation: 'tutDropIn 0.2s ease both',
                    zIndex: 10,
                  }}>
                    {groupEntries.map(([letter, apps]) => (
                      <div key={letter}>
                        <div style={{ padding: '6px 14px 2px', fontSize: 12, fontWeight: 700, color: TMC, letterSpacing: '0.08em' }}>{letter}</div>
                        {apps.map(app => {
                          const idx = app.name.toLowerCase().indexOf(q);
                          const before = app.name.slice(0, idx);
                          const match  = app.name.slice(idx, idx + q.length);
                          const after  = app.name.slice(idx + q.length);
                          return (
                            <div
                              key={app.id}
                              onClick={() => { setDropOpen(false); goToApp(app); }}
                              style={{
                                display: 'flex', alignItems: 'center', gap: 10,
                                padding: '7px 14px', cursor: 'pointer',
                                transition: 'background 0.1s',
                              }}
                              onMouseEnter={e => cs(e).background = SBG}
                              onMouseLeave={e => cs(e).background = 'transparent'}
                            >
                              <div style={{
                                width: 28, height: 28, borderRadius: 7, flexShrink: 0,
                                background: '#1a1a1a',
                                backgroundImage: `url(${app.icon})`,
                                backgroundSize: 'cover', backgroundPosition: 'center',
                              }} />
                              <span style={{ fontSize: 14, color: TC }}>
                                {before}<strong>{match}</strong>{after}
                              </span>
                            </div>
                          );
                        })}
                      </div>
                    ))}
                  </div>
                )}

                {/* No results */}
                {dropOpen && q && matchedApps.length === 0 && (
                  <div style={{
                    position: 'absolute', top: 'calc(100% + 6px)', left: 0, right: 0,
                    background: BG, border: CBR,
                    borderRadius: 14, padding: '16px',
                    textAlign: 'center', fontSize: 14, color: TMC,
                    boxShadow: '0 8px 28px rgba(0,0,0,0.1)',
                    animation: 'tutDropIn 0.2s ease both',
                    zIndex: 10,
                  }}>No apps found</div>
                )}
              </div>
            )}
          </div>
        )}
      </div>
    );
  }

  const WIDGET_DEFS = {
    fav:       { title: null,            label: 'Apps' },
    notif:     { title: 'Notifications', label: 'Notifications'  },
    analytics: { title: 'Analytics',     label: 'Analytics'      },
    tutorials: { title: 'Tutorials',      label: 'Tutorials'      },
  };

  function WidgetShell({ widgetId, onDragStart, onRemove, hoveredApp, setHoveredApp, onShowAll, btnRef, favoritedAppIds, onAppClick, onShowNotif, notifBtnRef, notifications, markRead, markUnread, dismissNotif, onShowAnalytics, analyticsBtnRef, onLearnMore }) {
    const def = WIDGET_DEFS[widgetId];
    const fs = useFontScale();
    return (
      <div style={{ border: '2px solid var(--t-card-border)', borderRadius: '12px', padding: '12px', paddingTop: '18px', position: 'relative', background: 'radial-gradient(ellipse at 30% 0%, var(--t-card-grad-top) 0%, var(--t-card) 60%)', height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column', overflow: 'visible' }}>
        <div style={{ position: 'absolute', top: '-13px', right: '8px', display: 'flex', gap: '4px', zIndex: 10 }}>
          <button onMouseDown={onDragStart} title="Drag"
            style={{ width: '22px', height: '22px', borderRadius: '4px', border: '1px solid var(--t-card-border)', background: SBG, cursor: 'grab', fontSize: '13px', padding: 0, lineHeight: 1, userSelect: 'none', color: TC }}>–</button>
          <button onClick={onRemove}
            style={{ width: '22px', height: '22px', borderRadius: '4px', border: '1px solid var(--t-card-border)', background: SBG, cursor: 'pointer', fontSize: '11px', padding: 0, lineHeight: 1, color: TC }}>✕</button>
        </div>

        {def.title && (
          <div style={{ textAlign: 'center', marginBottom: '8px', fontWeight: 700, fontSize: `${18 * fs}px`, fontFamily: FF, flexShrink: 0, color: TC }}>{def.title}</div>
        )}

        <div style={{ flex: 1, minHeight: 0, overflow: 'hidden' }}>
          {widgetId === 'fav' ? (
            <FavContent hoveredApp={hoveredApp} setHoveredApp={setHoveredApp} onShowAll={onShowAll} btnRef={btnRef} favoritedAppIds={favoritedAppIds} onAppClick={onAppClick} />
          ) : widgetId === 'notif' ? (
            <NotifContent onShowAll={onShowNotif} btnRef={notifBtnRef} notifications={notifications} markRead={markRead} markUnread={markUnread} dismiss={dismissNotif} />
          ) : widgetId === 'analytics' ? (
            <AnalyticsContent onSeeAll={onShowAnalytics} btnRef={analyticsBtnRef} />
          ) : widgetId === 'tutorials' ? (
            <TutorialsContent onLearnMore={onLearnMore} />
          ) : null}
        </div>
      </div>
    );
  }
  function SidebarAppIcon({ app, onAppClick }) {
    const [hovered, setHovered] = useState(false);
    if (!app) return (
      <div style={{ width: '56px', height: '56px', borderRadius: '12px', background: 'var(--t-restore-bg)', opacity: 0.4 }} />
    );
    return (
      <div style={{ position: 'relative', display: 'flex', justifyContent: 'center' }}>
        {hovered && (
          <div style={{
            position: 'absolute', right: 'calc(100% + 10px)', top: '50%',
            transform: 'translateY(-50%)',
            background: 'rgba(20,20,20,0.9)', color: '#fff',
            borderRadius: '8px', padding: '5px 10px',
            fontSize: '11px', whiteSpace: 'nowrap',
            zIndex: 100, lineHeight: 1.4,
            boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
            animation: 'tooltipIn 0.14s ease',
            pointerEvents: 'none',
          }}>
            {app.name}
          </div>
        )}
        <div
          onMouseEnter={() => setHovered(true)}
          onMouseLeave={() => setHovered(false)}
          onClick={() => onAppClick && onAppClick(app.id)}
          style={{
            width: '56px', height: '56px',
            borderRadius: '12px', background: '#1a1a1a',
            backgroundImage: `url(${app.icon})`,
            backgroundSize: 'cover', backgroundPosition: 'center',
            cursor: 'pointer',
            transition: 'transform 0.16s cubic-bezier(0.34,1.56,0.64,1), box-shadow 0.16s ease',
            transform: hovered ? 'scale(1.1)' : 'scale(1)',
            boxShadow: hovered ? '0 8px 20px rgba(0,0,0,0.22)' : '0 0 0 rgba(0,0,0,0)',
          }}
        />
      </div>
    );
  }
  function Dashboard() {
    const [hoveredApp, setHoveredApp]     = useState(null);
    const [slotMap, setSlotMap]           = useState({ fav:'fav', notif:'notif', analytics:'analytics', tutorials:'tutorials' });
    const [removed, setRemoved]           = useState(new Set());
    const [dragging, setDragging]         = useState(null);
    const [hoverSlot, setHoverSlot]       = useState(null);
    const [swappedSlots, setSwappedSlots] = useState(new Set());
    // 'hidden' | 'is-entering' | 'is-open' | 'is-exiting'
    const [appsPhase, setAppsPhase]           = useState('hidden');
    const [notifPhase, setNotifPhase]         = useState('hidden');
    const [analyticsPhase, setAnalyticsPhase] = useState('hidden');
    const [tutorialsOpen, setTutorialsOpen]   = useState(false);
    const [themesOpen, setThemesOpen]         = useState(false);
    const [activeTheme, setActiveTheme]       = useState('dark');
    const [resetConfirmOpen, setResetConfirmOpen] = useState(false);
    const [skippedAppIds, setSkippedAppIds] = useState(new Set());
    const [fontScale, setFontScale] = useState(1);

    const THEMES = [
      { id: 'default',      name: 'Light',         colors: { bg:'#fafafa', sidebar:'#f2f2f2', sidebarBorder:'#333', card:'#fff', cardBorder:'#e5e5e5', text:'#111', textMuted:'#666', restoreBg:'#f7f7f7', restoreBorder:'#ccc', accent:'#111' } },
      { id: 'dark',         name: 'Dark',           colors: { bg:'#1a1a1e', sidebar:'#111114', sidebarBorder:'#444', card:'#26262c', cardBorder:'#3a3a42', text:'#e8e8f0', textMuted:'#888', restoreBg:'#1e1e24', restoreBorder:'#444', accent:'#e8e8f0' } },
      { id: 'midnight',     name: 'Midnight',       colors: { bg:'#0d0e1a', sidebar:'#080910', sidebarBorder:'#3d3f6e', card:'#13152a', cardBorder:'#2a2d52', text:'#c5c9f7', textMuted:'#6b70b8', restoreBg:'#0f1120', restoreBorder:'#2a2d52', accent:'#7c82f5' } },
      { id: 'rose',         name: 'Rose Pine',      colors: { bg:'#faf4ed', sidebar:'#f2e9de', sidebarBorder:'#905e78', card:'#fffaf3', cardBorder:'#dbbfa3', text:'#575279', textMuted:'#9893a5', restoreBg:'#f2e9de', restoreBorder:'#d7bfa6', accent:'#905e78' } },
      { id: 'amoled',       name: 'AMOLED',         colors: { bg:'#000000', sidebar:'#000000', sidebarBorder:'#2a2a2a', card:'#0a0a0a', cardBorder:'#1e1e1e', text:'#ffffff', textMuted:'#666', restoreBg:'#050505', restoreBorder:'#2a2a2a', accent:'#ffffff' } },
      { id: 'highcontrast', name: 'High Contrast',  colors: { bg:'#ffffff', sidebar:'#ffffff', sidebarBorder:'#000000', card:'#ffffff', cardBorder:'#000000', text:'#000000', textMuted:'#000', restoreBg:'#eeeeee', restoreBorder:'#000000', accent:'#000000' } },
      { id: 'ocean',        name: 'Deep Ocean',     colors: { bg:'#0a1628', sidebar:'#061020', sidebarBorder:'#1a4a7a', card:'#0d1f3c', cardBorder:'#1a3a64', text:'#a8d4f5', textMuted:'#5a8ab0', restoreBg:'#0a1830', restoreBorder:'#1a3a64', accent:'#4fc3f7' } },
      { id: 'forest',       name: 'Forest',         colors: { bg:'#1a2416', sidebar:'#111a0e', sidebarBorder:'#3a6e2a', card:'#1e2d18', cardBorder:'#2d4a22', text:'#b8d4a0', textMuted:'#6a9456', restoreBg:'#182012', restoreBorder:'#2d4a22', accent:'#7ecb50' } },
      { id: 'sunset',       name: 'Sunset',         colors: { bg:'#1e1218', sidebar:'#160c12', sidebarBorder:'#7a2a4a', card:'#271520', cardBorder:'#4a1e34', text:'#f5c0d0', textMuted:'#b07080', restoreBg:'#1e1018', restoreBorder:'#4a1e34', accent:'#f06090' } },
      { id: 'solarized',    name: 'Solarized',      colors: { bg:'#fdf6e3', sidebar:'#eee8d5', sidebarBorder:'#657b83', card:'#fffcf0', cardBorder:'#ccc4a8', text:'#586e75', textMuted:'#93a1a1', restoreBg:'#eee8d5', restoreBorder:'#ccc4a8', accent:'#2aa198' } },
    ];

    const applyTheme = useCallback((themeId) => {
      const t = THEMES.find(th => th.id === themeId);
      if (!t) return;
      const root = document.documentElement;
      const c = t.colors;
      root.style.setProperty('--t-bg', c.bg);
      root.style.setProperty('--t-sidebar', c.sidebar);
      root.style.setProperty('--t-sidebar-border', c.sidebarBorder);
      root.style.setProperty('--t-card', c.card);
      root.style.setProperty('--t-card-border', c.cardBorder);
      root.style.setProperty('--t-text', c.text);
      root.style.setProperty('--t-text-muted', c.textMuted);
      root.style.setProperty('--t-restore-bg', c.restoreBg);
      root.style.setProperty('--t-restore-border', c.restoreBorder);
      root.style.setProperty('--t-accent', c.accent);
      // Compute gradient highlight stops: blend sidebar/card toward the accent color
      const blendHex = (base, tint, amt) => {
        const b = parseInt(base.slice(1), 16), ti = parseInt(tint.slice(1), 16);
        const r = Math.round(((b>>16)&255) * (1-amt) + ((ti>>16)&255) * amt);
        const g = Math.round(((b>>8)&255) * (1-amt) + ((ti>>8)&255) * amt);
        const bl = Math.round((b&255) * (1-amt) + (ti&255) * amt);
        return `#${r.toString(16).padStart(2,'0')}${g.toString(16).padStart(2,'0')}${bl.toString(16).padStart(2,'0')}`;
      };
      root.style.setProperty('--t-sidebar-grad-top', themeId === 'default' ? '#d8d8d8' : blendHex(c.sidebar, c.accent, 0.18));
      root.style.setProperty('--t-card-grad-top',    themeId === 'default' ? '#e2e2e2' : blendHex(c.card,    c.accent, 0.12));
      setActiveTheme(themeId);
      setThemesOpen(false);
    }, []);

    // Apply initial theme CSS variables on mount
    useEffect(() => { applyTheme('dark'); }, [applyTheme]);

    // Inject dynamic CSS for font scaling of class-based font sizes
    useEffect(() => {
      const id = 'apg-font-scale-style';
      let el = document.getElementById(id);
      if (!el) { el = document.createElement('style'); el.id = id; document.head.appendChild(el); }
      const s = fontScale;
      // Only override named CSS classes — no child selectors that cascade/compound
      el.textContent = `
        .restore-btn        { font-size: ${11 * s}px !important; font-family: var(--font-large) !important; }
        .themes-btn-label   { font-size: ${10 * s}px !important; font-family: var(--font-large) !important; }
        .apps-logo          { font-size: ${26 * s}px !important; font-family: var(--font-large) !important; font-weight: 900 !important; }
        .apps-search        { font-size: ${15 * s}px !important; font-family: var(--font-large) !important; }
        .apps-close-btn     { font-size: ${16 * s}px !important; }
        .apps-section-title { font-size: ${20 * s}px !important; font-family: var(--font-large) !important; font-weight: 800 !important; }
        .app-icon-label     { font-size: ${11 * s}px !important; font-family: var(--font-large) !important; }
      `;
      document.documentElement.style.setProperty('--t-fs', s);
    }, [fontScale]);

    // Inject persistent font-tier styles (runs once on mount)
    useEffect(() => {
      const id = 'apg-font-tier-style';
      if (document.getElementById(id)) return;
      const el = document.createElement('style');
      el.id = id;
      el.textContent = `

        /* Large: anything bold at 18px+ gets Helvetica */
        [style*="fontWeight: 700, fontFamily: FF"][style*="fontSize: 18"],
        [style*="fontWeight: 700"][style*="fontSize: 20"],
        [style*="fontWeight: 700"][style*="fontSize: 22"],
        [style*="fontWeight: 700"][style*="fontSize: 26"],
        [style*="fontWeight: 700"][style*="fontSize: 34"],
        [style*="fontWeight: 800"],
        [style*="fontWeight: 900"],
        [style*="font-weight: 700"][style*="font-size: 18"],
        [style*="font-weight: 800"],
        [style*="font-weight: 900"] {
          font-family: var(--font-large) !important;
        }

        /* Small: anything ≤10px gets Fjalla One */
        [style*="fontSize: 7"],
        [style*="fontSize: 8"],
        [style*="fontSize: 9"],
        [style*="fontSize: 10"] {
          font-family: var(--font-large) !important;
        }
      `;
      document.head.appendChild(el);
    }, []);

    const [dashExiting, setDashExiting]       = useState(false);
    // recentAppIds: most recently clicked first (index 0 = most recent)
    const [recentAppIds, setRecentAppIds]     = useState([]);
    // favoritedAppIds: apps the user has starred
    const [favoritedAppIds, setFavoritedAppIds] = useState([]);
    // detail popup for app clicks from outside the AppsOverlay (e.g. FavContent widget)
    const [dashboardPopupApp, setDashboardPopupApp] = useState(null);
    const [dashboardSkippedAppIds, setDashboardSkippedAppIds] = useState(new Set());
    const btnRef          = useRef(null);  // "Show All Apps" button
    const notifBtnRef     = useRef(null);  // "Show All Notifications" button
    const analyticsBtnRef = useRef(null);  // "See All" analytics button
    const [notifications, setNotifications] = useState(SAMPLE_NOTIFICATIONS);
    const nextIdRef = useRef(100);
    const markAllRead  = useCallback(() => setNotifications(prev => prev.map(n => ({ ...n, unread: false }))), []);
    const markRead     = useCallback((id) => setNotifications(prev => prev.map(n => n.id === id ? { ...n, unread: false } : n)), []);
    const markUnread   = useCallback((id) => setNotifications(prev => prev.map(n => n.id === id ? { ...n, unread: true  } : n)), []);
    const dismissNotif = useCallback((id) => setNotifications(prev => prev.filter(n => n.id !== id)), []);
    const addNotification = useCallback((notif) => {
      const id = nextIdRef.current++;
      // daysUntil: days from now until the reminder date
      const now = new Date(); now.setHours(0,0,0,0);
      const [_yr,_mo,_dy] = notif.date.split('-').map(Number);
      const due = new Date(_yr, _mo-1, _dy); due.setHours(0,0,0,0);
      const daysUntil = Math.round((due - now) / 86400000);
      if (daysUntil >= 7) return; // too far ahead, don't show
      const pinned = daysUntil <= 2;

      // Build a human-readable scheduled label
      const dayLabel = daysUntil === 0 ? 'Today' : daysUntil === 1 ? 'Tomorrow' : `In ${daysUntil} days`;
      const [yyyy, mm, dd] = notif.date.split('-');
      const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
      const dateFormatted = `${months[parseInt(mm,10)-1]} ${parseInt(dd,10)}, ${yyyy}`;
      let timeFormatted = '';
      if (notif.time) {
        const [hh, min] = notif.time.split(':');
        const h = parseInt(hh, 10);
        timeFormatted = `${h % 12 || 12}:${min} ${h < 12 ? 'AM' : 'PM'}`;
      }
      const scheduledLabel = timeFormatted ? `${dateFormatted} at ${timeFormatted}` : dateFormatted;

      const newNotif = {
        id,
        accent: '#d97706',
        label: 'REMINDER',
        category: 'Reminders',
        title: notif.title,
        body: notif.description,
        time: dayLabel,
        scheduledLabel,
        unread: true,
        pinned,
        isoDate: notif.date,
      };
      setNotifications(prev => pinned ? [newNotif, ...prev] : [...prev, newNotif]);
    }, []);
    const slotRefs = useRef({});
    ALL_SLOTS.forEach(s => { if (!slotRefs.current[s]) slotRefs.current[s] = { current: null }; });

    const handleFavorite = useCallback((appId) => {
      setFavoritedAppIds(prev => prev.includes(appId) ? prev : [appId, ...prev]);
    }, []);

    const handleUnfavorite = useCallback((appId) => {
      setFavoritedAppIds(prev => prev.filter(id => id !== appId));
    }, []);

    // Called when an app is clicked anywhere OUTSIDE the AppsOverlay (e.g. FavContent widget, sidebar)
    const handleAppClick = useCallback((appId) => {
      if (dashboardSkippedAppIds.has(appId) || skippedAppIds.has(appId)) {
        addToRecent(appId);
        return;
      }
      const app = APPS.find(a => a.id === appId);
      if (app) setDashboardPopupApp(app);
    }, [dashboardSkippedAppIds, skippedAppIds]);

    // Called only on confirmed "Launch" — adds to recent
    const addToRecent = useCallback((appId) => {
      setRecentAppIds(prev => {
        const filtered = prev.filter(id => id !== appId);
        return [appId, ...filtered];
      });
    }, []);

    const getSlotUnder = useCallback((mx, my) => {
      for (const s of ALL_SLOTS) {
        const el = slotRefs.current[s]?.current; if (!el) continue;
        const r = el.getBoundingClientRect();
        if (mx >= r.left && mx <= r.right && my >= r.top && my <= r.bottom) return s;
      }
      return null;
    }, []);

    useEffect(() => {
      if (!dragging) return;
      const onMove = e => {
        setDragging(d => d ? { ...d, prevMouseX: d.mouseX, mouseX: e.clientX, mouseY: e.clientY } : d);
        setHoverSlot(getSlotUnder(e.clientX, e.clientY));
      };
      const onUp = e => {
        const target = getSlotUnder(e.clientX, e.clientY);
        if (target && target !== dragging.fromSlot) {
          setSlotMap(prev => {
            const next = { ...prev };
            [next[target], next[dragging.fromSlot]] = [next[dragging.fromSlot], next[target]];
            return next;
          });
          setSwappedSlots(new Set([target, dragging.fromSlot]));
          setTimeout(() => setSwappedSlots(new Set()), 350);
        }
        setDragging(null); setHoverSlot(null);
      };
      window.addEventListener('mousemove', onMove);
      window.addEventListener('mouseup', onUp);
      return () => { window.removeEventListener('mousemove', onMove); window.removeEventListener('mouseup', onUp); };
    }, [dragging, getSlotUnder]);

    const startDrag = useCallback((widgetId, fromSlot, e) => {
      e.preventDefault();
      const el = slotRefs.current[fromSlot]?.current;
      const r  = el ? el.getBoundingClientRect() : { left: 0, top: 0, width: 200, height: 100 };
      setDragging({ widgetId, fromSlot, mouseX: e.clientX, mouseY: e.clientY,
        offsetX: e.clientX - r.left, offsetY: e.clientY - r.top,
        slotRect: { width: r.width, height: r.height } });
    }, []);

    const removeWidget  = useCallback(slotId => {
      const wid = slotMap[slotId]; if (!wid) return;
      setRemoved(p => new Set([...p, wid]));
      setSlotMap(p => ({ ...p, [slotId]: null }));
    }, [slotMap]);

    const restoreWidget = useCallback(wid => {
      const empty = ALL_SLOTS.find(s => slotMap[s] === null); if (!empty) return;
      setSlotMap(p => ({ ...p, [empty]: wid }));
      setRemoved(p => { const n = new Set(p); n.delete(wid); return n; });
    }, [slotMap]);
    const handleShowAll = useCallback(() => {
      // Find the WidgetShell card that wraps the button
      let card = btnRef.current?.parentElement;
      while (card && card.style && card.style.borderRadius !== '12px') card = card.parentElement;
      if (!card) card = btnRef.current;

      const r        = card.getBoundingClientRect();
      const sidebarW = 96; // nav sidebar width
      const panelW   = window.innerWidth - sidebarW;
      const vh       = window.innerHeight;

      // transform-origin relative to panel area (excludes sidebar)
      const ox = `${((r.left + r.width  / 2 - sidebarW) / panelW * 100).toFixed(2)}%`;
      const oy = `${((r.top  + r.height / 2)             / vh     * 100).toFixed(2)}%`;
      // initial scale: card size vs panel size
      const sx = (r.width  / panelW).toFixed(4);
      const sy = (r.height / vh    ).toFixed(4);

      window.__appsOrigin = { ox, oy, sx, sy };
      setAppsPhase('is-entering');
      setTimeout(() => setAppsPhase('is-open'), 480);
    }, []);

    const handleCloseApps = useCallback(() => {
      setAppsPhase('is-exiting');
      setTimeout(() => setAppsPhase('hidden'), 360);
    }, []);

    const handleShowNotif = useCallback(() => {
      let card = notifBtnRef.current?.parentElement;
      while (card && card.style && card.style.borderRadius !== '12px') card = card.parentElement;
      if (!card) card = notifBtnRef.current;
      const r        = card.getBoundingClientRect();
      const sidebarW = 96;
      const panelW   = window.innerWidth - sidebarW;
      const vh       = window.innerHeight;
      const ox = `${((r.left + r.width  / 2 - sidebarW) / panelW * 100).toFixed(2)}%`;
      const oy = `${((r.top  + r.height / 2)             / vh     * 100).toFixed(2)}%`;
      const sx = (r.width  / panelW).toFixed(4);
      const sy = (r.height / vh    ).toFixed(4);
      window.__notifOrigin = { ox, oy, sx, sy };
      setNotifPhase('is-entering');
      setTimeout(() => setNotifPhase('is-open'), 480);
    }, []);

    const handleCloseNotif = useCallback(() => {
      setNotifPhase('is-exiting');
      setTimeout(() => setNotifPhase('hidden'), 360);
    }, []);

    const handleShowAnalytics = useCallback(() => {
      let card = analyticsBtnRef.current?.parentElement;
      while (card && card.style && card.style.borderRadius !== '12px') card = card.parentElement;
      if (!card) card = analyticsBtnRef.current;
      const r        = card.getBoundingClientRect();
      const sidebarW = 96;
      const panelW   = window.innerWidth - sidebarW;
      const vh       = window.innerHeight;
      const ox = `${((r.left + r.width  / 2 - sidebarW) / panelW * 100).toFixed(2)}%`;
      const oy = `${((r.top  + r.height / 2)             / vh     * 100).toFixed(2)}%`;
      const sx = (r.width  / panelW).toFixed(4);
      const sy = (r.height / vh    ).toFixed(4);
      window.__analyticsOrigin = { ox, oy, sx, sy };
      setAnalyticsPhase('is-entering');
      setTimeout(() => setAnalyticsPhase('is-open'), 480);
    }, []);

    const handleCloseAnalytics = useCallback(() => {
      setAnalyticsPhase('is-exiting');
      setTimeout(() => setAnalyticsPhase('hidden'), 360);
    }, []);

    const handleLearnMore = useCallback(() => {
      setDashExiting(true);
      setTimeout(() => {
        setTutorialsOpen(true);
        setDashExiting(false);
      }, 420);
    }, []);

    const handleCloseTutorials = useCallback(() => {
      setTutorialsOpen(false);
    }, []);

    // Go home: close all overlays/panels when APG logo is clicked
    const handleGoHome = useCallback(() => {
      // Close apps panel immediately
      setAppsPhase(p => p !== 'hidden' ? 'is-exiting' : p);
      setTimeout(() => setAppsPhase(p => p === 'is-exiting' ? 'hidden' : p), 360);
      // Close notif panel
      setNotifPhase(p => p !== 'hidden' ? 'is-exiting' : p);
      setTimeout(() => setNotifPhase(p => p === 'is-exiting' ? 'hidden' : p), 360);
      // Close analytics panel
      setAnalyticsPhase(p => p !== 'hidden' ? 'is-exiting' : p);
      setTimeout(() => setAnalyticsPhase(p => p === 'is-exiting' ? 'hidden' : p), 360);
      // Close tutorials overlay
      setTutorialsOpen(false);
    }, []);

    useEffect(() => {
      window.addEventListener('apg-logo-click', handleGoHome);
      return () => window.removeEventListener('apg-logo-click', handleGoHome);
    }, [handleGoHome]);

    const removedList = [...removed];
    const hasSidebar  = removedList.length > 0;

    // Responsive: collapse to single column when viewport is narrow
    const [winW, setWinW] = useState(() => window.innerWidth);
    useEffect(() => {
      const onResize = () => setWinW(window.innerWidth);
      window.addEventListener('resize', onResize);
      return () => window.removeEventListener('resize', onResize);
    }, []);
    // Breakpoint: ≤700px triggers single-column stacked layout
    const isNarrow = winW <= 700 || (fontScale >= 1.2 && winW <= 1000) || fontScale >= 1.35;

    const rowCols = row =>
      isNarrow
        ? '1fr'  // single column: each slot fills full width
        : row.slots.map(s => (slotMap[s] !== null || dragging?.fromSlot === s) ? `${BASE_COLS[s]}fr` : '0fr').join(' ');

    const gtr = () =>
      isNarrow
        ? 'auto' // rows size to content in stacked mode
        : GRID_ROWS.map(row =>
            row.slots.some(s => slotMap[s] !== null || dragging?.fromSlot === s) ? '1fr' : '0fr'
          ).join(' ');

    const renderSlot = slotId => {
      const widgetId       = slotMap[slotId];
      const isDraggingThis = dragging?.fromSlot === slotId;
      const isDropTarget   = hoverSlot === slotId && dragging && dragging.fromSlot !== slotId;
      const isOtherActive  = dragging && !isDraggingThis && hoverSlot !== slotId;
      const isSnapping     = swappedSlots.has(slotId);

      let cls = '';
      if (isDraggingThis)    cls = 'slot-source';
      else if (isDropTarget) cls = 'slot-highlight';
      else if (isOtherActive) cls = 'drag-active-dim';
      if (isSnapping)        cls = 'widget-snap';

      return (
        <div key={slotId} ref={el => { slotRefs.current[slotId].current = el; }}
          className={cls} style={{ position: 'relative', minHeight: 0, minWidth: 0, ...(isNarrow ? { height: 260 } : {}) }}>
          {isDraggingThis && (
            <div style={{ position: 'absolute', inset: 0, border: '2px dashed #aaa', borderRadius: '12px', background: 'rgba(0,0,0,0.03)', zIndex: 4, pointerEvents: 'none' }} />
          )}
          {widgetId ? (
            <WidgetShell key={widgetId} widgetId={widgetId}
              onDragStart={e => startDrag(widgetId, slotId, e)}
              onRemove={() => removeWidget(slotId)}
              hoveredApp={hoveredApp} setHoveredApp={setHoveredApp}
              onShowAll={handleShowAll} btnRef={btnRef}
              favoritedAppIds={favoritedAppIds}
              onAppClick={handleAppClick}
              onShowNotif={handleShowNotif} notifBtnRef={notifBtnRef}
              notifications={notifications} markRead={markRead} markUnread={markUnread} dismissNotif={dismissNotif}
              onShowAnalytics={handleShowAnalytics} analyticsBtnRef={analyticsBtnRef}
              onLearnMore={handleLearnMore}
            />
          ) : null}
        </div>
      );
    };

    return (
      <FontScaleContext.Provider value={fontScale}>
      <ThemeContext.Provider value={activeTheme}>
      <div style={{ display: 'flex', height: '100vh', overflow: 'hidden', background: 'var(--t-bg)' }}>

        {/* Restore sidebar */}
        <div className={`restore-sidebar ${hasSidebar ? 'open' : 'closed'}`}>
          {hasSidebar && (<>
            <div style={{ fontSize: '10px', fontWeight: 700, color: TMC, textAlign: 'center', letterSpacing: '0.05em', textTransform: 'uppercase', lineHeight: 1.3 }}>
              Removed<br/>Tiles
            </div>
            <div style={{ width: '100%', height: '1px', background: 'var(--t-card-border)' }} />
            {removedList.map(wid => (
              <button key={wid} className="restore-btn" onClick={() => restoreWidget(wid)}>
                + {WIDGET_DEFS[wid].label}
              </button>
            ))}
          </>)}
        </div>

        {/* Nav sidebar */}
        <div style={{ width: '96px', background: 'linear-gradient(180deg, var(--t-sidebar-grad-top) 0%, var(--t-sidebar) 55%)', borderRight: `2px solid var(--t-sidebar-border)`, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '20px 0', flexShrink: 0 }}>
          {/* Themes button — top of sidebar */}
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: '8px', flexShrink: 0 }}
               onClick={() => setThemesOpen(o => !o)}>
            <button className="themes-btn-icon" title="Themes">
              {/* Palette icon */}
              <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="var(--t-accent)" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="13.5" cy="6.5" r="1.5" fill="var(--t-accent)" stroke="none"/>
                <circle cx="17.5" cy="10.5" r="1.5" fill="var(--t-accent)" stroke="none"/>
                <circle cx="8.5" cy="7.5" r="1.5" fill="var(--t-accent)" stroke="none"/>
                <circle cx="6.5" cy="12.5" r="1.5" fill="var(--t-accent)" stroke="none"/>
                <path d="M12 2C6.5 2 2 6.5 2 12s4.5 10 10 10c.926 0 1.648-.746 1.648-1.688 0-.437-.18-.835-.437-1.125-.29-.289-.438-.652-.438-1.125a1.64 1.64 0 0 1 1.668-1.668h1.996c3.051 0 5.555-2.503 5.555-5.554C21.998 6.918 17.503 2 12 2z"/>
              </svg>
            </button>
            <span className="themes-btn-label">Themes</span>
          </div>
          <div style={{ width: '50%', height: '1.5px', background: 'var(--t-sidebar-border)', opacity: 0.25, margin: '4px 0 12px' }} />
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '16px' }}>
            {[0,1,2].map(i => <SidebarAppIcon key={i} app={APPS.find(a => a.id === recentAppIds[i])} onAppClick={handleAppClick} />)}
          </div>
        </div>

        {/* Main content */}
        <div style={{
          flex: 1, padding: '20px', background: 'var(--t-bg)',
          overflow: isNarrow ? 'auto' : 'hidden',
          display: 'flex', flexDirection: 'column', minHeight: 0,
          transition: 'opacity 0.38s ease, transform 0.38s cubic-bezier(0.4,0,0.2,1)',
          opacity: dashExiting ? 0 : 1,
          transform: dashExiting ? 'scale(0.93)' : 'scale(1)',
          pointerEvents: dashExiting ? 'none' : 'auto',
        }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px', flexShrink: 0 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
              <APGLogo />
              <button
                onClick={() => setResetConfirmOpen(true)}
                style={{
                  padding: '7px 14px', borderRadius: 8, cursor: 'pointer',
                  background: 'none', border: '1.5px solid var(--t-card-border)',
                  fontSize: 12, fontWeight: 600, fontFamily: FF,
                  color: TMC, letterSpacing: '0.01em',
                  transition: 'background 0.13s, color 0.13s, border-color 0.13s',
                  whiteSpace: 'nowrap',
                }}
                onMouseEnter={e => { cs(e).background = SBG; cs(e).borderColor = TMC; cs(e).color = TC; }}
                onMouseLeave={e => { cs(e).background = 'none'; cs(e).borderColor = 'var(--t-card-border)'; cs(e).color = TMC; }}
              >Reset All Preferences</button>
<div style={{
                display: 'flex', alignItems: 'center', gap: 10,
                padding: '6px 14px', borderRadius: 12,
                border: '1.5px solid var(--t-card-border)',
                background: SBG,
                boxShadow: 'inset 0 1px 3px rgba(0,0,0,0.12)',
                minWidth: 260,
              }}>
                {/* Small Aa */}
                <span style={{ fontSize: 11, fontWeight: 800, color: TMC, userSelect: 'none', flexShrink: 0, lineHeight: 1 }}>Aa</span>

                {/* Custom slider track */}
                <div style={{ flex: 1, position: 'relative', height: 20, display: 'flex', alignItems: 'center' }}>
                  {/* Track background */}
                  <div style={{
                    position: 'absolute', left: 0, right: 0, height: 4,
                    borderRadius: 99, background: 'var(--t-card-border)',
                    overflow: 'hidden',
                  }}>
                    {/* Filled portion */}
                    <div style={{
                      height: '100%',
                      width: `${((fontScale - 1) / 0.4) * 100}%`,
                      background: ACC,
                      borderRadius: 99,
                      transition: 'width 0.1s ease',
                    }} />
                  </div>

                  {/* Step dots */}
                  {[0, 0.1, 0.2, 0.3, 0.4].map((offset, i) => {
                    const pct = (offset / 0.4) * 100;
                    const active = fontScale >= 1 + offset - 0.01;
                    return (
                      <div key={i} style={{
                        position: 'absolute',
                        left: `calc(${pct}% - 3px)`,
                        width: 6, height: 6, borderRadius: '50%',
                        background: active ? ACC : 'var(--t-card-border)',
                        border: active ? '2px solid var(--t-sidebar)' : '2px solid var(--t-card)',
                        zIndex: 1,
                        transition: 'background 0.1s ease',
                        pointerEvents: 'none',
                      }} />
                    );
                  })}

                  {/* Actual invisible input on top */}
                  <input
                    type="range"
                    min="1" max="1.4" step="0.05"
                    value={fontScale}
                    onChange={e => setFontScale(parseFloat(e.target.value))}
                    style={{
                      position: 'absolute', left: 0, right: 0, width: '100%',
                      opacity: 0, cursor: 'pointer', height: 20, margin: 0,
                      zIndex: 2,
                    }}
                    title="Accessibility Font Size"
                  />

                  {/* Custom thumb */}
                  <div style={{
                    position: 'absolute',
                    left: `calc(${((fontScale - 1) / 0.4) * 100}% - 9px)`,
                    width: 18, height: 18, borderRadius: '50%',
                    background: ACC,
                    border: '2.5px solid var(--t-sidebar)',
                    boxShadow: '0 2px 8px rgba(0,0,0,0.25)',
                    zIndex: 1,
                    transition: 'left 0.1s ease',
                    pointerEvents: 'none',
                  }} />
                </div>

                {/* Large Aa + current scale label */}
                <div style={{ display: 'flex', alignItems: 'baseline', gap: 4, flexShrink: 0 }}>
                  <span style={{ fontSize: 16, fontWeight: 800, color: TC, userSelect: 'none', lineHeight: 1 }}>Aa</span>
                  <span style={{ fontSize: 9, fontFamily: FF, fontWeight: 700, color: TMC, userSelect: 'none', lineHeight: 1, letterSpacing: '0.02em' }}>
                    {fontScale === 1 ? '100%' : `+${Math.round((fontScale - 1) * 100)}%`}
                  </span>
                </div>
              </div>
            </div>
            <h1 style={{ margin: 0, fontWeight: 300, fontSize: `${34 * fontScale}px`, letterSpacing: '-0.5px', color: TC }}>Dashboard</h1>
          </div>
{resetConfirmOpen && (
            <div
              onClick={() => setResetConfirmOpen(false)}
              style={{
                position: 'fixed', inset: 0, zIndex: 800,
                background: 'rgba(0,0,0,0.45)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                animation: 'menuIn 0.18s cubic-bezier(0.34,1.56,0.64,1)',
              }}
            >
              <div
                onClick={e => e.stopPropagation()}

                style={{
                  background: BG, borderRadius: 16,
                  padding: '28px 28px 24px', width: 400,
                  boxShadow: '0 24px 64px rgba(0,0,0,0.28)',
                  display: 'flex', flexDirection: 'column', gap: 14,
                  animation: 'menuIn 0.22s cubic-bezier(0.34,1.56,0.64,1)',
                }}
              >
                {/* Icon + Title */}
                <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                  <div style={{ width: 38, height: 38, borderRadius: 10, background: 'rgba(220,38,38,0.12)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#dc2626" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                      <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/>
                      <line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/>
                    </svg>
                  </div>
                  <div style={{ fontSize: 18, fontWeight: 800, fontFamily: FF, color: TC }}>Reset All Preferences?</div>
                </div>

                {/* Body */}
                <p style={{ margin: 0, fontSize: 14, color: TMC, lineHeight: 1.6 }}>
                  This will:
                </p>
                <ul style={{ margin: 0, padding: '0 0 0 18px', fontSize: 14, color: TMC, lineHeight: 1.8 }}>
                  <li>Reset your theme back to the default theme</li>
                  <li>Reset all launch preferences (don't show this again checkboxes)</li>
                  <li>Font sizes/Accessibility settings</li>
                </ul>
                <p style={{ margin: 0, fontSize: 13, color: TMC, fontStyle: 'italic' }}>
                  This cannot be undone.
                </p>

                {/* Buttons */}
                <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end', marginTop: 4 }}>
                  <button
                    onClick={() => setResetConfirmOpen(false)}
                    style={{
                      padding: '9px 20px', borderRadius: 8, cursor: 'pointer',
                      background: 'none', border: '1.5px solid var(--t-card-border)',
                      fontSize: 14, fontWeight: 600, fontFamily: FF, color: TMC,
                      transition: 'background 0.12s',
                    }}
                    onMouseEnter={e => cs(e).background = SBG}
                    onMouseLeave={e => cs(e).background = 'none'}
                  >Go Back</button>
                  <button
                    onClick={() => {
                      applyTheme('dark');
                      setFontScale(1);
                      setDashboardSkippedAppIds(new Set());
                      setSkippedAppIds(new Set());
                      setResetConfirmOpen(false);
                    }}
                    style={{
                      padding: '9px 22px', borderRadius: 8, cursor: 'pointer',
                      background: '#dc2626', border: 'none',
                      color: '#fff', fontSize: 14, fontWeight: 700, fontFamily: FF,
                      transition: 'opacity 0.12s',
                    }}
                    onMouseEnter={e=>cs(e).opacity='0.85'} onMouseLeave={e=>cs(e).opacity='1'}
                  >Confirm</button>
                </div>
              </div>
            </div>
          )}

          <div style={{
            ...(isNarrow
              ? { display: 'flex', flexDirection: 'column', gap: '16px' }
              : { flex: 1, minHeight: 0, display: 'grid', gridTemplateRows: gtr(), gap: '16px', transition: 'grid-template-rows 0.22s cubic-bezier(0.4,0,0.2,1)' }
            )
          }}>
            {isNarrow
              ? /* Narrow: every slot is its own row, all slots flat */
                ALL_SLOTS.filter(s => slotMap[s] !== null).map(slotId => renderSlot(slotId))
              : /* Wide: grouped rows */
                GRID_ROWS.map((row, ri) => (
                  <div key={ri} style={{ display: 'grid', gridTemplateColumns: rowCols(row), gap: '20px', minHeight: 0, transition: 'grid-template-columns 0.22s cubic-bezier(0.4,0,0.2,1)' }}>
                    {row.slots.map(renderSlot)}
                  </div>
                ))
            }
          </div>
        </div>

        {/* Drag ghost — live clone of the dragged widget */}
        {dragging && (() => {
          const vx   = dragging.mouseX - (dragging.prevMouseX || dragging.mouseX);
          const tilt = Math.max(-5, Math.min(5, vx * 0.35));
          return (
            <div className="widget-dragging" style={{
              position: 'fixed',
              left: dragging.mouseX - dragging.offsetX,
              top:  dragging.mouseY - dragging.offsetY,
              width: dragging.slotRect.width,
              height: dragging.slotRect.height,
              pointerEvents: 'none', zIndex: 1000,
              transform: `scale(1.03) rotate(${tilt}deg)`,
              transition: 'transform 0.06s ease',
            }}>
              <WidgetShell
                widgetId={dragging.widgetId}
                onDragStart={() => {}}
                onRemove={() => {}}
                hoveredApp={hoveredApp} setHoveredApp={setHoveredApp}
                onShowAll={handleShowAll} btnRef={{ current: null }}
                favoritedAppIds={favoritedAppIds}
                onAppClick={handleAppClick}
                onShowNotif={handleShowNotif} notifBtnRef={{ current: null }}
                notifications={notifications} markRead={markRead} markUnread={markUnread} dismissNotif={dismissNotif}
                onShowAnalytics={handleShowAnalytics} analyticsBtnRef={{ current: null }}
              />
            </div>
          );
        })()}

        {/* Apps overlay */}
        <AppsOverlay phase={appsPhase} onClose={handleCloseApps} recentAppIds={recentAppIds} onAppClick={addToRecent} favoritedAppIds={favoritedAppIds} onFavorite={handleFavorite} onUnfavorite={handleUnfavorite} skippedAppIds={skippedAppIds} setSkippedAppIds={setSkippedAppIds} />
        {/* Notifications overlay */}
        <NotificationsOverlay phase={notifPhase} onClose={handleCloseNotif} notifications={notifications} markAllRead={markAllRead} markRead={markRead} markUnread={markUnread} dismiss={dismissNotif} addNotification={addNotification} />
        {/* Analytics overlay */}
        <AnalyticsOverlay phase={analyticsPhase} onClose={handleCloseAnalytics} />
        {/* Tutorials overlay */}
        {tutorialsOpen && <TutorialsOverlay onClose={handleCloseTutorials} />}
        {/* Themes panel */}
        {themesOpen && (
          <div className="themes-panel-overlay" onClick={() => setThemesOpen(false)}>
            <div className="themes-panel" onClick={e => e.stopPropagation()}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
                <div style={{ fontSize: '16px', fontWeight: 800, color: TC, letterSpacing: '-0.3px' }}>Themes</div>
                <button onClick={() => setThemesOpen(false)} style={{ width: 28, height: 28, borderRadius: '50%', border: '1.5px solid var(--t-card-border)', background: SBG, cursor: 'pointer', fontSize: 14, color: TMC, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>✕</button>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {[
                  { label: 'Normal',        ids: ['default', 'dark'] },
                  { label: 'Accessibility', ids: ['amoled', 'highcontrast'] },
                  { label: 'Color Themes',  ids: ['ocean', 'forest', 'sunset', 'solarized', 'midnight', 'rose'] },
                ].map(cat => (
                  <div key={cat.label}>
                    <div style={{ fontSize: 10, fontFamily: FF, fontWeight: 800, color: TMC, letterSpacing: '0.08em', textTransform: 'uppercase', marginBottom: '8px' }}>{cat.label}</div>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px' }}>
                      {cat.ids.map(id => {
                        const theme = THEMES.find(t => t.id === id);
                        if (!theme) return null;
                        const isActive = activeTheme === theme.id;
                        return (
                          <button key={theme.id} onClick={() => applyTheme(theme.id)} style={{
                            display: 'flex', alignItems: 'center', gap: 10,
                            padding: '10px 12px', borderRadius: 12, cursor: 'pointer',
                            border: isActive ? `2px solid var(--t-accent)` : '2px solid var(--t-card-border)',
                            background: isActive ? SBG : BG,
                            transition: 'transform 0.14s, border-color 0.14s, background 0.14s',
                            fontFamily: FF, outline: 'none',
                          }}
                          onMouseEnter={e => cs(e).transform = 'scale(1.03)'}
                          onMouseLeave={e => cs(e).transform = 'scale(1)'}
                          >
                            {/* Mini colour swatch */}
                            <div style={{ width: 28, height: 28, borderRadius: 8, flexShrink: 0, overflow: 'hidden', border: '1.5px solid rgba(128,128,128,0.2)', display: 'grid', gridTemplateColumns: '1fr 1fr', gridTemplateRows: '1fr 1fr' }}>
                              <div style={{ background: theme.colors.bg }} />
                              <div style={{ background: theme.colors.sidebar }} />
                              <div style={{ background: theme.colors.card }} />
                              <div style={{ background: theme.colors.accent }} />
                            </div>
                            <div style={{ fontSize: 12, fontWeight: 700, color: TC, lineHeight: 1.2 }}>{theme.name}</div>
                            {isActive && (
                              <div style={{ marginLeft: 'auto', width: 16, height: 16, borderRadius: '50%', background: ACC, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                                <svg width="9" height="9" viewBox="0 0 10 10"><polyline points="1.5,5 4,7.5 8.5,2.5" stroke={THEMES.find(t=>t.id===activeTheme)?.colors.bg||'#1a1a1e'} strokeWidth="1.8" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>
                              </div>
                            )}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
        {/* App detail popup (from FavContent widget or sidebar) */}
        {dashboardPopupApp && (
          <AppDetailPopup
            app={dashboardPopupApp}
            onLaunch={(dontShow) => { addToRecent(dashboardPopupApp.id); if (dontShow) { setDashboardSkippedAppIds(prev => new Set([...prev, dashboardPopupApp.id])); setSkippedAppIds(prev => new Set([...prev, dashboardPopupApp.id])); } setDashboardPopupApp(null); }}
            onBack={(dontShow) => { if (dontShow) { setDashboardSkippedAppIds(prev => new Set([...prev, dashboardPopupApp.id])); setSkippedAppIds(prev => new Set([...prev, dashboardPopupApp.id])); } setDashboardPopupApp(null); }}
          />
        )}
      </div>
    </ThemeContext.Provider>
    </FontScaleContext.Provider>
    );
  }

  ReactDOM.createRoot(document.getElementById('root')).render(<Dashboard />);